    def reset(self) -> None:
        if self.state_dir.exists():
            shutil.rmtree(self.state_dir)

    def append_audit(self, event_type: str, scope: dict[str, str], subject: dict[str, str], details: dict[str, Any]) -> dict[str, Any]:
        self.audit_path.parent.mkdir(parents=True, exist_ok=True)
        with self.audit_path.open("a+") as file:
            fcntl.flock(file.fileno(), fcntl.LOCK_EX)
            try:
                file.seek(0)
                previous_hash = "0" * 64
                for line in file.read().splitlines():
                    if line.strip():
                        previous_hash = json.loads(line)["event_hash"]
                event_without_hash = {
                    "schema_version": "cs.audit_event.v0",
                    "event_type": event_type,
                    "occurred_at": utc_now(),
                    "tenant_id": scope["tenant_id"],
                    "owner_id": scope["owner_id"],
                    "namespace_id": scope["namespace_id"],
                    "workspace_id": scope["workspace_id"],
                    "subject": subject,
                    "details": details,
                    "previous_hash": previous_hash,
                }
                event_hash = _json_hash(event_without_hash)
                event = dict(event_without_hash)
                event["event_id"] = f"audit_{event_hash[:16]}"
                event["event_hash"] = event_hash
                file.seek(0, os.SEEK_END)
                file.write(json.dumps(event, sort_keys=True) + "\n")
                file.flush()
                return event
            finally:
                fcntl.flock(file.fileno(), fcntl.LOCK_UN)

    def _audit_snapshot_lines(self) -> list[str]:
        try:
            with self.audit_path.open() as file:
                fcntl.flock(file.fileno(), fcntl.LOCK_SH)
                try:
                    return file.read().splitlines()
                finally:
                    fcntl.flock(file.fileno(), fcntl.LOCK_UN)
        except FileNotFoundError:
            return []

    def verify_audit(self) -> dict[str, Any]:
        return self._verify_audit_lines(self._audit_snapshot_lines())

    def _verify_audit_lines(self, lines: list[str]) -> dict[str, Any]:
        previous_hash = "0" * 64
        event_count = 0
        errors: list[dict[str, str]] = []
        for line_no, line in enumerate(lines, start=1):
            if not line.strip():
                continue
            event_count += 1
            try:
                event = json.loads(line)
            except ValueError as error:
                errors.append({"line": str(line_no), "code": "AUDIT_JSON_INVALID", "message": str(error)})
                continue
            event_hash = event.get("event_hash")
            event_without_hash = dict(event)
            event_without_hash.pop("event_id", None)
            event_without_hash.pop("event_hash", None)
            calculated = _json_hash(event_without_hash)
            if event.get("previous_hash") != previous_hash:
                errors.append({"line": str(line_no), "code": "AUDIT_PREVIOUS_HASH_MISMATCH", "message": "Previous hash does not match prior event."})
            if event_hash != calculated:
                errors.append({"line": str(line_no), "code": "AUDIT_EVENT_HASH_MISMATCH", "message": "Event hash does not match event body."})
            previous_hash = event_hash or ""
        return {"status": "success" if not errors else "failed", "event_count": event_count, "errors": errors}

    def artifact_path(self, artifact_id: str, scope: dict[str, str] | None = None) -> Path:
        base = self.record_dir if scope is None else self.record_dir / scope_key(scope)
        return self._safe_record_path(base, artifact_id)

    def _safe_record_path(self, base: Path, record_id: str) -> Path:
        if not re.fullmatch(r"[A-Za-z0-9_-]{1,200}", record_id):
            raise ValueError("Invalid record id.")
        resolved_base = base.resolve()
        path = (resolved_base / f"{record_id}.json").resolve()
        if path.parent != resolved_base:
            raise ValueError("Record path escapes its storage directory.")
        return path

    def derived_representation_path(self, representation_id: str) -> Path:
        if not DERIVED_REPRESENTATION_ID_RE.fullmatch(representation_id):
            raise ValueError("Invalid derived representation id.")
        return self.derived_representation_dir / f"{representation_id}.json"

    def search_snapshot_path(self, snapshot_id: str) -> Path:
        return self._safe_record_path(self.state_dir / "search" / "snapshots", snapshot_id)

    def evidence_bundle_path(self, bundle_id: str) -> Path:
        return self._safe_record_path(self.state_dir / "evidence" / "bundles", bundle_id)

    def evidence_chunk_path(self, chunk_id: str) -> Path:
        if not EVIDENCE_CHUNK_ID_RE.fullmatch(chunk_id):
            raise ValueError("Invalid evidence chunk id.")
        base = self.evidence_chunk_dir.resolve()
        path = (base / f"{chunk_id}.json").resolve()
        if path.parent != base:
            raise ValueError("Evidence chunk path escapes its storage directory.")
        return path

