    def propose_product_improvement(self, lesson_id: str, *, proposal: str, scope: dict[str, str]) -> dict[str, Any]:
        lesson = self.get_lesson_candidate(lesson_id)
        if lesson is None:
            return {"status": "not_found", "resource": "lesson"}
