    def _workspace_mode_record(self, mode: str, scope: dict[str, str]) -> dict[str, Any]:
        behaviors = {
            "manual": {
                "label": "Manual",
                "action_proposals_allowed": True,
                "autonomous_execution_allowed": False,
                "approval_required_for_execution": True,
                "description": "CornerStone may propose work, but execution requires explicit owner action.",
            },
            "assist": {
                "label": "Assist",
                "action_proposals_allowed": True,
                "autonomous_execution_allowed": False,
                "approval_required_for_execution": True,
                "description": "CornerStone can draft briefs, claims, mission contracts, and action cards without autonomous execution.",
            },
            "autopilot": {
                "label": "Autopilot",
                "action_proposals_allowed": True,
                "autonomous_execution_allowed": True,
                "approval_required_for_execution": False,
                "description": "CornerStone may execute allowed low-risk mission actions inside the active scope and policy boundary.",
            },
            "locked": {
                "label": "Locked",
                "action_proposals_allowed": False,
                "autonomous_execution_allowed": False,
                "approval_required_for_execution": True,
                "description": "CornerStone records evidence and audit only; action proposal and execution are blocked.",
            },
        }
        return {
            "schema_version": "cs.workspace_mode.v0",
            "mode": mode,
            "scope": scope,
            "behaviors": behaviors[mode],
            "available_modes": [
                {
                    "mode": key,
                    "label": value["label"],
                    "autonomous_execution_allowed": value["autonomous_execution_allowed"],
                    "approval_required_for_execution": value["approval_required_for_execution"],
                }
                for key, value in behaviors.items()
            ],
            "updated_at": utc_now(),
        }

    def set_workspace_mode(self, mode: str, scope: dict[str, str]) -> dict[str, Any]:
        record = self._workspace_mode_record(mode, scope)
        _write_json(self.workspace_path(scope), record)
        event = self.append_audit(
            "workspace.mode.set",
            scope,
            {"type": "workspace", "id": scope_key(scope)},
            {
                "mode": mode,
                "autonomous_execution_allowed": record["behaviors"]["autonomous_execution_allowed"],
            },
        )
        return {"workspace_mode": record, "audit_event": event}

    def create_mission_contract(
        self,
        goal: str,
        scope: dict[str, str],
        *,
        claim_id: str | None = None,
        evidence_bundle_id: str | None = None,
    ) -> dict[str, Any]:
        claim = self.get_claim(claim_id) if claim_id else None
        if claim_id and claim is None:
            return {"status": "not_found", "resource": "claim"}
        if claim and claim.get("scope") != scope:
            return {"status": "scope_denied", "resource_scope": claim.get("scope")}

        bundle_id = evidence_bundle_id
        if claim and not bundle_id:
            bundle_id = claim.get("evidence_bundle", {}).get("evidence_bundle_id")
        bundle = self.get_evidence_bundle(bundle_id) if bundle_id else None
        if bundle_id and bundle is None:
            return {"status": "not_found", "resource": "evidence_bundle"}
        if bundle and bundle.get("filters") != scope:
            return {"status": "scope_denied", "resource_scope": bundle.get("filters")}

        evidence_artifact_refs = []
        if claim:
            evidence_artifact_refs.extend(claim.get("evidence_bundle", {}).get("artifact_refs", []))
        if bundle:
            evidence_artifact_refs.extend(f"artifact:{item['artifact_id']}" for item in bundle.get("evidence_items", []))
        evidence_artifact_refs = sorted(set(evidence_artifact_refs))
        if not evidence_artifact_refs:
            return {"status": "evidence_required"}

        mode = self.get_workspace_mode(scope)
        contract_base = {
            "schema_version": "cs.mission_goal_contract.v0",
            "status": "draft",
            "goal": goal,
            "scope": scope,
            "workspace_mode": mode["mode"],
            "source_claim": {
                "claim_id": claim.get("claim_id") if claim else None,
                "statement": claim.get("statement") if claim else None,
                "trust_state": claim.get("trust_state") if claim else None,
            },
            "evidence": {
                "evidence_bundle_id": bundle_id,
                "artifact_refs": evidence_artifact_refs,
                "search_snapshot_id": bundle.get("search_snapshot_id") if bundle else None,
            },
            "risk_state": "controlled_policy_required",
            "allowed_actions": [
                "internal_status_update",
                "draft_task",
                "refresh_brief",
            ],
            "forbidden_actions": [
                "external_writeback_without_workflow_action",
                "cross_namespace_access",
                "destructive_change",
                "secret_exfiltration",
            ],
            "success_criteria": [
                "Use attached evidence refs for every durable claim or action.",
                "Record every action proposal, dry-run, policy decision, approval, result, and audit event.",
            ],
            "stop_conditions": [
                "Policy denies scope, egress, connector capability, data sensitivity, or workspace mode.",
                "A required approval is missing.",
                "A requested action is outside the mission contract.",
            ],
            "review_cadence": "owner review required before high-risk execution; after-action audit after every run",
            "escalation_rules": [
                "Escalate high-risk, destructive, sensitive, cross-namespace, or external writeback actions.",
                "Escalate when evidence coverage is insufficient or policy decision is deny.",
            ],
            "evidence_expectations": [
                "Evidence Bundle with at least one artifact reference.",
                "Dry-run diff and expected impact before side-effecting action.",
                "Audit refs for every policy and action transition.",
            ],
            "authority": {
                "may_do": ["propose action cards", "run allowed low-risk internal actions in Autopilot mode"],
                "may_not_do": ["direct external writeback", "cross-namespace action", "destructive action without approval"],
                "requires_escalation": ["high-risk", "external_writeback", "sensitive", "out_of_contract"],
                "controls": ["pause", "stop", "revoke", "reduce_scope"],
            },
            "created_at": utc_now(),
        }
        mission_id = f"mission_{_json_hash(contract_base)[:16]}"
        contract = dict(contract_base)
        contract["mission_id"] = mission_id
        _write_json(self.mission_path(mission_id), contract)
        event = self.append_audit(
            "mission.contract.created",
            scope,
            {"type": "mission", "id": mission_id},
            {
                "claim_id": claim_id,
                "evidence_bundle_id": bundle_id,
                "workspace_mode": mode["mode"],
                "allowed_actions": contract["allowed_actions"],
            },
        )
        return {"mission": contract, "audit_event": event}

    def activate_mission(self, mission_id: str, scope: dict[str, str], mode: str = "autopilot") -> dict[str, Any]:
        mission = self.get_mission(mission_id)
        if mission is None:
            return {"status": "not_found"}
        if mission.get("scope") != scope:
            return {"status": "scope_denied", "resource_scope": mission.get("scope")}
        mode_result = self.set_workspace_mode(mode, scope)
        activated = dict(mission)
        activated["status"] = "active"
        activated["workspace_mode"] = mode
        activated["activated_at"] = utc_now()
        activated["authority_view"] = {
            "may_act_in_scope": scope,
            "allowed_actions": activated.get("allowed_actions", []),
            "forbidden_actions": activated.get("forbidden_actions", []),
            "requires_escalation": activated.get("authority", {}).get("requires_escalation", []),
            "pause_stop_revoke": activated.get("authority", {}).get("controls", []),
        }
        _write_json(self.mission_path(mission_id), activated)
        event = self.append_audit(
            "mission.activated",
            scope,
            {"type": "mission", "id": mission_id},
            {
                "mode": mode,
                "allowed_actions": activated.get("allowed_actions", []),
                "forbidden_actions": activated.get("forbidden_actions", []),
            },
        )
        return {"mission": activated, "workspace_mode": mode_result["workspace_mode"], "audit_events": [mode_result["audit_event"], event]}

    def _action_policy(
        self,
        mission: dict[str, Any],
        action_kind: str,
        risk: str,
        scope: dict[str, str],
        connector: str,
        direct: bool = False,
    ) -> dict[str, Any]:
        workspace_mode = self.get_workspace_mode(scope)
        mode = workspace_mode["mode"]
        allowed_actions = set(mission.get("allowed_actions", []))
        external = action_kind == "external_writeback"
        high_risk = risk in {"high", "destructive", "sensitive"} or external

        if direct:
            decision = "deny"
            policy = "workflow_action_path_required"
            reason = "Direct provider writeback is denied. Use a governed Workflow/Action path with dry-run, policy, approval, result, and audit."
            approval_required = True
            can_execute_now = False
            execution_status = "blocked_direct_write"
        elif mode == "locked":
            decision = "deny"
            policy = "workspace_mode_locked"
            reason = "Workspace mode is Locked, so action proposal and execution are disabled."
            approval_required = True
            can_execute_now = False
            execution_status = "blocked_by_workspace_mode"
        elif action_kind not in allowed_actions and not external:
            decision = "escalate"
            policy = "mission_contract_action_scope"
            reason = "Requested action is outside the Mission Goal Contract allowed actions."
            approval_required = True
            can_execute_now = False
            execution_status = "escalated_out_of_contract"
        elif high_risk:
            decision = "requires_approval"
            policy = "high_risk_action_requires_approval"
            reason = "High-risk or external writeback action requires owner approval before execution."
            approval_required = True
            can_execute_now = False
            execution_status = "pending_approval"
        elif mode != "autopilot":
            decision = "deny"
            policy = "workspace_mode_no_autonomous_execution"
            reason = "Workspace mode does not allow autonomous execution."
            approval_required = True
            can_execute_now = False
            execution_status = "blocked_by_workspace_mode"
        else:
            decision = "allow"
            policy = "low_risk_autopilot_allowed"
            reason = "Low-risk action is inside the active Mission Goal Contract and workspace Autopilot boundary."
            approval_required = False
            can_execute_now = True
            execution_status = "ready_to_execute"

        return {
            "schema_version": "cs.policy_decision.v0",
            "id": f"policy_{_json_hash({'mission_id': mission.get('mission_id'), 'action_kind': action_kind, 'risk': risk, 'mode': mode, 'direct': direct})[:16]}",
            "decision": decision,
            "policy": policy,
            "reason": reason,
            "scope": scope,
            "workspace_mode": mode,
            "mission_id": mission.get("mission_id"),
            "action_kind": action_kind,
            "risk": risk,
            "connector": connector,
            "approval_required": approval_required,
            "can_execute_now": can_execute_now,
            "execution_status": execution_status,
            "resolution_path": [
                "Use an active Mission Goal Contract.",
                "Keep action inside allowed actions and owner namespace.",
                "Run dry-run and request owner approval when policy requires it.",
            ],
            "decided_at": utc_now(),
        }

    def propose_action(
        self,
        mission_id: str,
        claim_id: str,
        action_kind: str,
        risk: str,
        scope: dict[str, str],
        *,
        goal: str,
        connector: str = "mock_connector",
        target: str = "mock://local-target",
        ontology_object_refs: list[str] | None = None,
    ) -> dict[str, Any]:
        mission = self.get_mission(mission_id)
        if mission is None:
            return {"status": "not_found", "resource": "mission"}
        if mission.get("scope") != scope:
            return {"status": "scope_denied", "resource_scope": mission.get("scope")}
        claim = self.get_claim(claim_id)
        if claim is None:
            return {"status": "not_found", "resource": "claim"}
        if claim.get("scope") != scope:
            return {"status": "scope_denied", "resource_scope": claim.get("scope")}
        if not claim.get("evidence_bundle", {}).get("artifact_refs"):
            return {"status": "evidence_required"}

        policy = self._action_policy(mission, action_kind, risk, scope, connector)
        if not (
            claim.get("status") == "approved"
            and claim.get("trust_state") == "approved"
            and claim.get("statement_support", {}).get("semantic_support_verified") is True
            and claim.get("authority", {}).get("can_drive_autonomous_action") is True
        ):
            policy = {
                **policy,
                "decision": "deny",
                "policy": "action_source_claim_authority_required",
                "reason_code": "CS_ACTION_CLAIM_AUTHORITY_REQUIRED",
                "reason": "The Action can remain a review draft, but its source Claim has no semantic or action authority.",
                "approval_required": True,
                "can_execute_now": False,
                "execution_status": "blocked_by_claim_authority",
                "resolution_path": [
                    "Review the Action Card without executing it.",
                    "Complete statement-level semantic support review before granting Claim authority.",
                ],
            }
        expected_connector_calls = 1 if action_kind == "external_writeback" else 0
        ontology_refs = ontology_object_refs or claim.get("ontology_context", {}).get("object_refs", [])
        dry_run_base = {
            "schema_version": "cs.action_dry_run.v0",
            "mission_id": mission_id,
            "claim_id": claim_id,
            "action_kind": action_kind,
            "goal": goal,
            "scope": scope,
            "diff": {
                "before": "no side effect applied",
                "after": f"would perform {action_kind} against {target}",
            },
            "expected_impact": {
                "risk": risk,
                "target": target,
                "connector": connector,
                "expected_connector_calls": expected_connector_calls,
                "mock_connector_calls": expected_connector_calls,
                "real_external_http_calls": 0,
                "ontology_object_refs": ontology_refs,
                "ontology_impact_visible": bool(ontology_refs),
            },
            "rollback_or_compensation": {
                "dry_run_side_effects_applied": False,
                "rollback_required_for_dry_run": False,
                "automatic_rollback_available": False,
                "separate_governed_compensation_required_after_execution": action_kind == "external_writeback",
                "note": (
                    "Dry-run applies no side effect. If a recorded execution needs correction, create a separate "
                    "governed compensation Action; no automatic rollback is implied."
                ),
            },
            "policy_decision": policy,
            "created_at": utc_now(),
        }
        dry_run = dict(dry_run_base)
        dry_run["dry_run_id"] = f"dryrun_{_json_hash(dry_run_base)[:16]}"
        card_base = {
            "schema_version": "cs.action_card.v0",
            "mission_id": mission_id,
            "source_claim_id": claim_id,
            "goal": goal,
            "scope": scope,
            "evidence": claim.get("evidence_bundle"),
            "risk": risk,
            "action_kind": action_kind,
            "connector_boundary": {
                "mediated_by": "ConnectorHub",
                "connector": connector,
                "direct_provider_access": False,
                "credentials_exposed_to_agent": False,
                "mocked": True,
            },
            "ontology_impact": {
                "object_refs": ontology_refs,
                "impact_note": "Ontology context can shape local impact review, but it does not authorize external writeback.",
                "real_external_http_calls": 0,
            },
            "dry_run": dry_run,
            "policy_decision": policy,
            "approval": {
                "required": policy["approval_required"],
                "status": "not_required" if not policy["approval_required"] else "pending",
                "approver": None,
            },
            "execution": {
                "status": policy["execution_status"],
                "can_execute_now": policy["can_execute_now"],
                "result": None,
            },
            "created_at": utc_now(),
        }
        action_id = f"action_{_json_hash(card_base)[:16]}"
        card = dict(card_base)
        card["action_id"] = action_id
        _write_json(self.action_path(action_id), card)
        event = self.append_audit(
            "action.card.proposed",
            scope,
            {"type": "action", "id": action_id},
            {
                "mission_id": mission_id,
                "claim_id": claim_id,
                "action_kind": action_kind,
                "risk": risk,
                "policy": policy["policy"],
                "decision": policy["decision"],
                "dry_run_id": dry_run["dry_run_id"],
                "ontology_object_refs": ontology_refs,
            },
        )
        card["audit_ref"] = f"audit:{event['event_id']}"
        _write_json(self.action_path(action_id), card)
        return {"action_card": card, "audit_event": event}

    def _is_authorized_action_approver(self, approver: str | None, scope: dict[str, str]) -> bool:
        if not approver:
            return False
        return approver in AUTHORIZED_ACTION_APPROVER_ALIASES or approver == scope.get("owner_id")

    def _action_execution_denial_policy(
        self,
        action: dict[str, Any],
        scope: dict[str, str],
        *,
        reason_code: str,
        policy: str,
        reason: str,
        resolution_path: list[str],
        mission_id: str | None = None,
    ) -> dict[str, Any]:
        payload = {
            "action_id": action.get("action_id"),
            "reason_code": reason_code,
            "policy": policy,
            "mission_id": mission_id or action.get("mission_id"),
            "scope": scope,
        }
        return {
            "schema_version": "cs.policy_decision.v0",
            "id": f"policy_{_json_hash(payload)[:16]}",
            "decision": "deny",
            "policy": policy,
            "reason_code": reason_code,
            "reason": reason,
            "scope": scope,
            "workspace_mode": self.get_workspace_mode(scope)["mode"],
            "mission_id": mission_id or action.get("mission_id"),
            "action_kind": action.get("action_kind"),
            "risk": action.get("risk"),
            "connector": action.get("connector_boundary", {}).get("connector"),
            "approval_required": True,
            "can_execute_now": False,
            "execution_status": "blocked_by_action_safety_envelope",
            "resolution_path": resolution_path,
            "decided_at": utc_now(),
        }

    def _action_safety_envelope(
        self,
        action: dict[str, Any],
        scope: dict[str, str],
        *,
        status: str,
        reason_code: str | None,
        policy_decision: dict[str, Any],
        preflight: dict[str, Any] | None = None,
    ) -> dict[str, Any]:
        preflight_ref = action.get("connector_preflight", {}).get("preflight_ref")
        expected_preflight_binding = action_preflight_binding_for_action(action)
        observed_preflight_binding = preflight.get("action_binding") if preflight else None
        payload = {
            "action_id": action.get("action_id"),
            "status": status,
            "reason_code": reason_code,
            "policy_id": policy_decision.get("id"),
            "preflight_ref": preflight_ref,
            "action_binding": expected_preflight_binding,
        }
        envelope_id = f"asafe_{_json_hash(payload)[:16]}"
        envelope = {
            "schema_version": "cs.action_safety_envelope.v0",
            "action_safety_envelope_id": envelope_id,
            "status": status,
            "reason_code": reason_code,
            "scope": scope,
            "action_id": action.get("action_id"),
            "mission_id": action.get("mission_id"),
            "claim_id": action.get("source_claim_id"),
            "evidence_bundle_id": action.get("evidence", {}).get("evidence_bundle_id"),
            "artifact_refs": action.get("evidence", {}).get("artifact_refs", []),
            "policy_ref": f"policy:{policy_decision.get('id')}",
            "approval": action.get("approval", {}),
            "connector_preflight_ref": preflight_ref,
            "connector_preflight_decision": preflight.get("decision") if preflight else None,
            "connector_preflight_reason_codes": preflight.get("reason_codes", []) if preflight else [],
            "expected_action_binding": expected_preflight_binding,
            "connector_preflight_action_binding": observed_preflight_binding,
            "connector_preflight_binding_current": observed_preflight_binding == expected_preflight_binding
            if preflight
            else False,
            "gate_results": preflight.get("gate_results", {}) if preflight else {},
            "idempotency_key_present": bool(
                str((preflight or {}).get("policy_input", {}).get("idempotency_key") or "").strip()
            ),
            "external_http_calls": 0,
            "provider_mutations": 0,
            "real_provider_calls": 0,
            "execution_result_created": False,
            "workflow_run_started": False,
            "created_at": utc_now(),
        }
        _write_json(self.action_safety_envelope_path(envelope_id), envelope)
        return envelope

    def _connector_preflight_from_action(self, action: dict[str, Any], scope: dict[str, str]) -> dict[str, Any] | None:
        preflight_ref = action.get("connector_preflight", {}).get("preflight_ref")
        if not isinstance(preflight_ref, str) or not preflight_ref.startswith("connector_action_preflight:"):
            return None
        preflight_id = preflight_ref.split(":", 1)[1]
        path = self.connector_action_preflight_path(preflight_id)
        if not path.exists():
            return None
        preflight = json.loads(path.read_text())
        if preflight.get("scope") != scope:
            return None
        return preflight

    def _validate_action_execution_safety(
        self,
        action: dict[str, Any],
        scope: dict[str, str],
        policy: dict[str, Any],
    ) -> tuple[dict[str, Any] | None, dict[str, Any] | None]:
        if not action.get("evidence", {}).get("artifact_refs"):
            decision = self._action_execution_denial_policy(
                action,
                scope,
                reason_code="CS_ACTION_EVIDENCE_REQUIRED",
                policy="action_execution_evidence_required",
                reason="Action execution requires an Evidence Bundle with at least one artifact reference.",
                resolution_path=["Attach an Evidence Bundle with Artifact refs before requesting execution."],
            )
            return decision, self._action_safety_envelope(action, scope, status="denied", reason_code=decision["reason_code"], policy_decision=decision)

        if policy.get("decision") in {"deny", "escalate"}:
            denied_policy = dict(policy)
            denied_policy["reason_code"] = "CS_ACTION_POLICY_DENIED"
            return denied_policy, self._action_safety_envelope(action, scope, status="denied", reason_code="CS_ACTION_POLICY_DENIED", policy_decision=denied_policy)

        approval = action.get("approval", {})
        if policy.get("approval_required") and approval.get("status") != "approved":
            decision = self._action_execution_denial_policy(
                action,
                scope,
                reason_code="CS_ACTION_AUTHORIZED_APPROVAL_REQUIRED",
                policy="action_execution_authorized_approval_required",
                reason="Action execution requires authorized approval before any connector call.",
                resolution_path=["Review the dry-run and preflight, then approve with an authorized owner principal."],
            )
            return decision, self._action_safety_envelope(action, scope, status="denied", reason_code=decision["reason_code"], policy_decision=decision)

        if policy.get("approval_required") and not self._is_authorized_action_approver(approval.get("approver"), scope):
            decision = self._action_execution_denial_policy(
                action,
                scope,
                reason_code="CS_ACTION_APPROVER_UNAUTHORIZED",
                policy="action_execution_approver_authority_required",
                reason="Action approval was not recorded by an authorized owner principal.",
                resolution_path=["Re-approve the Action Card as the owner or an authorized owner delegate."],
            )
            return decision, self._action_safety_envelope(action, scope, status="denied", reason_code=decision["reason_code"], policy_decision=decision)

        side_effecting_connector_action = (
            action.get("action_kind") in SIDE_EFFECTING_ACTION_KINDS
            and action.get("connector_boundary", {}).get("connector") != "mock_connector"
        )
        if not side_effecting_connector_action:
            return None, None

        preflight = self._connector_preflight_from_action(action, scope)
        if preflight is None:
            decision = self._action_execution_denial_policy(
                action,
                scope,
                reason_code="CS_ACTION_PREFLIGHT_REQUIRED",
                policy="connector_action_preflight_required",
                reason="Side-effecting connector execution requires a current ConnectorHub preflight.",
                resolution_path=["Run connector action-preflight for this Action Card before execution."],
            )
            return decision, self._action_safety_envelope(action, scope, status="denied", reason_code=decision["reason_code"], policy_decision=decision)
        gate_results = preflight.get("gate_results", {})
        if gate_results.get("permission_granted") is not True:
            decision = self._action_execution_denial_policy(
                action,
                scope,
                reason_code="CS_ACTION_CONNECTOR_PERMISSION_REQUIRED",
                policy="connector_action_permission_required",
                reason="ConnectorHub preflight does not show the required provider permission.",
                resolution_path=["Grant the required connector permission and rerun preflight."],
            )
            return decision, self._action_safety_envelope(action, scope, status="denied", reason_code=decision["reason_code"], policy_decision=decision, preflight=preflight)
        idempotency_key = str(preflight.get("policy_input", {}).get("idempotency_key") or "")
        if not idempotency_key.strip():
            decision = self._action_execution_denial_policy(
                action,
                scope,
                reason_code="CS_ACTION_IDEMPOTENCY_REQUIRED",
                policy="connector_action_idempotency_required",
                reason="Side-effecting connector execution requires a stable idempotency key from preflight.",
                resolution_path=["Provide a stable idempotency key and rerun preflight."],
            )
            return decision, self._action_safety_envelope(action, scope, status="denied", reason_code=decision["reason_code"], policy_decision=decision, preflight=preflight)
        if preflight.get("action_id") != action.get("action_id") or preflight.get("decision") != "allow":
            decision = self._action_execution_denial_policy(
                action,
                scope,
                reason_code="CS_ACTION_PREFLIGHT_NOT_ALLOWED",
                policy="connector_action_preflight_must_allow",
                reason="ConnectorHub preflight did not allow this Action Card.",
                resolution_path=["Resolve the preflight denial reason and rerun preflight before execution."],
            )
            return decision, self._action_safety_envelope(action, scope, status="denied", reason_code=decision["reason_code"], policy_decision=decision, preflight=preflight)

        expected_binding = action_preflight_binding_for_action(action)
        observed_binding = preflight.get("action_binding")
        policy_input = preflight.get("policy_input", {})
        risk = preflight.get("risk", {})
        binding_current = (
            observed_binding == expected_binding
            and preflight.get("connector_kind") == expected_binding.get("connector")
            and risk.get("product_risk") == expected_binding.get("risk")
            and policy_input.get("product_policy_ref") == expected_binding.get("product_policy_ref")
            and preflight.get("target") == expected_binding.get("target")
        )
        if not binding_current:
            decision = self._action_execution_denial_policy(
                action,
                scope,
                reason_code="CS_ACTION_PREFLIGHT_STALE",
                policy="connector_action_preflight_must_match_current_action",
                reason="ConnectorHub preflight binding no longer matches the current ActionCard safety inputs.",
                resolution_path=["Rerun dry-run and ConnectorHub preflight after changing ActionCard inputs."],
            )
            return decision, self._action_safety_envelope(action, scope, status="denied", reason_code=decision["reason_code"], policy_decision=decision, preflight=preflight)
        expected_target = action.get("dry_run", {}).get("expected_impact", {}).get("target")
        if preflight.get("target") != expected_target:
            decision = self._action_execution_denial_policy(
                action,
                scope,
                reason_code="CS_ACTION_PREFLIGHT_STALE",
                policy="connector_action_preflight_must_match_current_action",
                reason="ConnectorHub preflight target no longer matches the current ActionCard dry-run target.",
                resolution_path=["Rerun dry-run and ConnectorHub preflight after changing ActionCard inputs."],
            )
            return decision, self._action_safety_envelope(action, scope, status="denied", reason_code=decision["reason_code"], policy_decision=decision, preflight=preflight)
        return None, None

    def _action_lock_path(self, action_id: str) -> Path:
        return self.state_dir / "locks" / "actions" / f"{sha256_bytes(action_id.encode('utf-8'))}.lock"

    def _action_claim_authority_denial(
        self,
        action: dict[str, Any],
        scope: dict[str, str],
    ) -> dict[str, Any] | None:
        claim_id = str(action.get("source_claim_id") or "")
        claim = self.get_claim(claim_id) if claim_id else None
        claim_authorized = bool(
            claim
            and claim.get("scope") == scope
            and claim.get("status") == "approved"
            and claim.get("trust_state") == "approved"
            and claim.get("statement_support", {}).get("semantic_support_verified") is True
            and claim.get("authority", {}).get("can_drive_autonomous_action") is True
        )
        if claim_authorized:
            return None
        return self._action_execution_denial_policy(
            action,
            scope,
            reason_code="CS_ACTION_CLAIM_AUTHORITY_REQUIRED",
            policy="action_source_claim_authority_required",
            reason="Action approval or execution requires a current semantically verified Claim with explicit action authority.",
            resolution_path=[
                "Keep this Action Card as a review draft.",
                "Complete statement-level semantic support review before granting Claim authority.",
                "Create a new governed Action only after the source Claim is currently authorized.",
            ],
        )

    def approve_action(self, action_id: str, scope: dict[str, str], approver: str = "owner") -> dict[str, Any]:
        lock_path = self._action_lock_path(action_id)
        lock_path.parent.mkdir(parents=True, exist_ok=True)
        with lock_path.open("a+") as lock_file:
            fcntl.flock(lock_file.fileno(), fcntl.LOCK_EX)
            try:
                return self._approve_action_locked(action_id, scope, approver)
            finally:
                fcntl.flock(lock_file.fileno(), fcntl.LOCK_UN)

    def _approve_action_locked(self, action_id: str, scope: dict[str, str], approver: str) -> dict[str, Any]:
        action = self.get_action(action_id)
        if action is None:
            return {"status": "not_found"}
        if action.get("scope") != scope:
            return {"status": "scope_denied", "resource_scope": action.get("scope")}
        if action.get("execution", {}).get("status") == "executed":
            return {"status": "already_executed", "action_card": action}
        claim_authority_denial = self._action_claim_authority_denial(action, scope)
        if claim_authority_denial is not None:
            event = self.append_audit(
                "action.approval.denied",
                scope,
                {"type": "action", "id": action_id},
                {
                    "mission_id": action.get("mission_id"),
                    "reason_code": claim_authority_denial["reason_code"],
                    "source_claim_id": action.get("source_claim_id"),
                    "external_http_calls": 0,
                    "provider_mutations": 0,
                },
            )
            return {
                "status": "policy_denied",
                "reason_code": claim_authority_denial["reason_code"],
                "policy_decision": claim_authority_denial,
                "action_card": action,
                "audit_event": event,
            }
        if not action.get("approval", {}).get("required"):
            return {"status": "approval_not_required", "action_card": action}
        if not self._is_authorized_action_approver(approver, scope):
            policy = self._action_execution_denial_policy(
                action,
                scope,
                reason_code="CS_ACTION_APPROVER_UNAUTHORIZED",
                policy="action_approval_approver_authority_required",
                reason="Action approval must be recorded by the owner or an authorized owner delegate.",
                resolution_path=["Approve the Action Card as the owner or an authorized owner delegate."],
            )
            event = self.append_audit(
                "action.approval.denied",
                scope,
                {"type": "action", "id": action_id},
                {
                    "mission_id": action.get("mission_id"),
                    "approver": approver,
                    "reason_code": policy["reason_code"],
                    "external_http_calls": 0,
                    "provider_mutations": 0,
                },
            )
            return {"status": "policy_denied", "policy_decision": policy, "action_card": action, "audit_event": event}

        approved = dict(action)
        approved["approval"] = {
            "required": True,
            "status": "approved",
            "approver": approver,
            "approved_at": utc_now(),
        }
        approved["execution"] = dict(approved["execution"])
        approved["execution"]["status"] = "ready_to_execute"
        approved["execution"]["can_execute_now"] = True
        _write_json(self.action_path(action_id), approved)
        event = self.append_audit(
            "action.approved",
            scope,
            {"type": "action", "id": action_id},
            {
                "mission_id": approved.get("mission_id"),
                "approver": approver,
                "policy": approved.get("policy_decision", {}).get("policy"),
            },
        )
        return {"action_card": approved, "audit_event": event}

    def _connector_action_execution_records(
        self,
        action: dict[str, Any],
        scope: dict[str, str],
        policy: dict[str, Any],
        preflight: dict[str, Any],
    ) -> dict[str, Any]:
        action_id = str(action.get("action_id") or "")
        idempotency_key = str(preflight.get("policy_input", {}).get("idempotency_key") or "")
        policy_input = preflight.get("policy_input", {}) if isinstance(preflight.get("policy_input"), dict) else {}
        input_schema = preflight.get("input_schema", {}) if isinstance(preflight.get("input_schema"), dict) else {}
        idempotency_scope = {
            "connector_id": preflight.get("connector_id"),
            "provider_pack_ref": preflight.get("provider_pack_ref"),
        }
        request_digest_payload = {
            "scope": scope,
            "connector_id": preflight.get("connector_id"),
            "provider_pack_ref": preflight.get("provider_pack_ref"),
            "action_type": preflight.get("action_type"),
            "target": preflight.get("target"),
            "source_policy_ref": policy_input.get("source_policy_ref"),
            "selected_resources": sorted(str(item) for item in policy_input.get("selected_resources", [])),
            "required_permission": policy_input.get("required_permission"),
            "input_fingerprint": input_schema.get("input_fingerprint"),
        }
        request_digest = sha256_bytes(json.dumps(request_digest_payload, sort_keys=True).encode("utf-8"))
        idempotency_base = {
            "schema_version": "cs.connector_action_idempotency.v1",
            "scope": scope,
            "idempotency_key": idempotency_key,
            "idempotency_scope": idempotency_scope,
        }
        idempotency_id = f"idemp_{_json_hash(idempotency_base)[:16]}"
        idempotency_path = self.idempotency_path(idempotency_id)
        existing_idempotency = _read_json(idempotency_path) if idempotency_path.exists() else None
        if existing_idempotency and existing_idempotency.get("action_result_id"):
            if existing_idempotency.get("request_digest") != request_digest:
                conflict_base = {
                    "schema_version": "cs.connector_action_idempotency_conflict.v1",
                    "status": "conflict_rejected",
                    "scope": scope,
                    "idempotency_id": idempotency_id,
                    "idempotency_key_fingerprint": sha256_bytes(idempotency_key.encode("utf-8")),
                    "existing_action_id": existing_idempotency.get("action_id"),
                    "incoming_action_id": action_id,
                    "existing_request_digest": existing_idempotency.get("request_digest"),
                    "incoming_request_digest": request_digest,
                    "existing_request_digest_payload": existing_idempotency.get("request_digest_payload"),
                    "incoming_request_digest_payload": request_digest_payload,
                    "reason_code": "CS_ACTION_IDEMPOTENCY_CONFLICT",
                    "decision": "deny",
                    "duplicate_side_effect_count": 0,
                    "external_http_calls": 0,
                    "provider_mutations": 0,
                    "real_provider_calls": 0,
                    "automatic_compensation_executed": False,
                    "compensation": {
                        "expectation_visible": True,
                        "automatic_compensation_executed": False,
                        "separate_governed_action_required": True,
                        "candidate_reason": "Conflicting idempotency intent was rejected before provider execution.",
                    },
                    "created_at": utc_now(),
                }
                conflict = dict(conflict_base)
                conflict["idempotency_conflict_id"] = f"idempconf_{_json_hash(conflict_base)[:16]}"
                updated_idempotency = dict(existing_idempotency)
                conflicts = list(updated_idempotency.get("conflict_attempts", []))
                conflicts.append(conflict)
                updated_idempotency["conflict_attempts"] = conflicts
                updated_idempotency["conflict_attempt_count"] = len(conflicts)
                updated_idempotency["conflicting_intent_rejected"] = True
                updated_idempotency["last_conflict"] = conflict
                retry_status = dict(updated_idempotency.get("retry_status", {}))
                retry_status["conflicting_intent_rejected"] = True
                retry_status["conflict_attempt_count"] = len(conflicts)
                retry_status["last_conflict_id"] = conflict["idempotency_conflict_id"]
                updated_idempotency["retry_status"] = retry_status
                updated_idempotency["updated_at"] = utc_now()
                _write_json(idempotency_path, updated_idempotency)
                return {
                    "status": "conflict",
                    "idempotency": updated_idempotency,
                    "idempotency_conflict": conflict,
                    "duplicate_side_effect_count": 0,
                }

            updated_idempotency = dict(existing_idempotency)
            retry_status = dict(updated_idempotency.get("retry_status", {}))
            duplicate_retry_count = int(retry_status.get("duplicate_retry_count", 0) or 0) + 1
            retry_status.update(
                {
                    "status": "replayed_existing_result",
                    "duplicate_retry_count": duplicate_retry_count,
                    "same_key_same_request_digest_returned_existing_result": True,
                    "process_restart_replay_safe": True,
                    "timeout_before_response_reconciled": True,
                    "ambiguous_provider_response_reconciled": True,
                    "provider_duplicate_response_reconciled": True,
                    "last_replay_at": utc_now(),
                }
            )
            updated_idempotency["retry_status"] = retry_status
            updated_idempotency["duplicate_request"] = {
                "accepted": False,
                "deduplicated": True,
                "side_effect_count": 0,
                "returned_existing_result": True,
                "duplicate_retry_count": duplicate_retry_count,
            }
            updated_idempotency["duplicate_side_effect_count"] = 0
            updated_idempotency["updated_at"] = utc_now()
            _write_json(idempotency_path, updated_idempotency)
            result_path = self.action_result_path(str(existing_idempotency["action_result_id"]))
            workflow_path = self.workflow_run_path(str(existing_idempotency.get("workflow_run_id") or ""))
            receipt_path = self.connector_provider_receipt_path(str(existing_idempotency.get("provider_receipt_id") or ""))
            bundle = self.get_evidence_bundle(str(existing_idempotency.get("outcome_evidence_bundle_id") or ""))
            outcome = self.get_connected_outcome(str(existing_idempotency.get("connected_outcome_id") or ""))
            return {
                "status": "replayed",
                "idempotency": updated_idempotency,
                "action_result": _read_json(result_path) if result_path.exists() else action.get("execution", {}).get("result", {}),
                "workflow_run": _read_json(workflow_path) if workflow_path.exists() else {},
                "provider_receipt": _read_json(receipt_path) if receipt_path.exists() else {},
                "outcome_artifact": self.get_artifact(str(existing_idempotency.get("outcome_artifact_id") or ""), scope) or {},
                "outcome_evidence_bundle": bundle or {},
                "connected_outcome": outcome or {},
                "duplicate_side_effect_count": 0,
            }

        workflow_base = {
            "schema_version": "cs.workflow_run.v0",
            "status": "succeeded",
            "scope": scope,
            "action_id": action_id,
            "mission_id": action.get("mission_id"),
            "claim_id": action.get("source_claim_id"),
            "execution_adapter": "ConnectorHub",
            "connector_id": preflight.get("connector_id"),
            "provider_pack_ref": preflight.get("provider_pack_ref"),
            "preflight_ref": f"connector_action_preflight:{preflight.get('connector_action_preflight_id')}",
            "policy_ref": f"policy:{policy.get('id')}",
            "approval": action.get("approval", {}),
            "action_type": preflight.get("action_type"),
            "target": preflight.get("target"),
            "idempotency_id": idempotency_id,
            "idempotency_key_fingerprint": sha256_bytes(idempotency_key.encode("utf-8")),
            "request_digest": request_digest,
            "direct_provider_access": False,
            "credentials_exposed_to_agent": False,
            "external_http_calls": 0,
            "workflow_run_started": True,
            "created_at": utc_now(),
        }
        workflow_run_id = f"wrun_{_json_hash(workflow_base)[:16]}"
        workflow_run = dict(workflow_base)
        workflow_run["workflow_run_id"] = workflow_run_id

        provider_receipt_base = {
            "schema_version": "cs.connector_provider_receipt.v1",
            "status": "success",
            "scope": scope,
            "action_id": action_id,
            "workflow_run_id": workflow_run_id,
            "connector_id": preflight.get("connector_id"),
            "provider_pack_ref": preflight.get("provider_pack_ref"),
            "action_type": preflight.get("action_type"),
            "target": preflight.get("target"),
            "idempotency_id": idempotency_id,
            "idempotency_key_fingerprint": sha256_bytes(idempotency_key.encode("utf-8")),
            "request_digest": request_digest,
            "fixture_provider_effect_count": 1,
            "duplicate_side_effect_count": 0,
            "direct_provider_access": False,
            "external_http_calls": 0,
            "raw_provider_payload_persisted": False,
            "credential_values_exposed": False,
            "provider_response_state": "ambiguous_success_reconciled_by_idempotency",
            "result_metadata": {
                "ticket_id": "CS-1001",
                "new_status": "waiting_on_customer",
                "provider_outcome_ref": "supportdesk:ticket:CS-1001:status:waiting_on_customer",
            },
            "created_at": utc_now(),
        }
        provider_receipt_id = f"cprec_{_json_hash(provider_receipt_base)[:16]}"
        provider_receipt = dict(provider_receipt_base)
        provider_receipt["provider_receipt_id"] = provider_receipt_id

        outcome_text = "\n".join(
            [
                "ConnectorHub governed action outcome",
                f"Action: {action_id}",
                f"WorkflowRun: {workflow_run_id}",
                f"Provider receipt: {provider_receipt_id}",
                "Support ticket CS-1001 moved to waiting_on_customer.",
                "Outcome was produced by the local supportdesk fixture through ConnectorHub mediation.",
                "No direct Product or agent provider call was made; external_http_calls=0; duplicate_side_effect_count=0.",
            ]
        )
        artifact_result = self.ingest_text_artifact(
            outcome_text,
            scope,
            source_type="connector_action_outcome",
            source_ref=f"connector_provider_receipt:{provider_receipt_id}",
            trust="trusted",
        )
        outcome_artifact = artifact_result["artifact"]
        search_result = self.search("ConnectorHub governed action outcome support ticket CS-1001", **scope)
        bundle_result = self.create_evidence_bundle(search_result["snapshot"]["search_snapshot_id"], scope)
        outcome_bundle = bundle_result["bundle"]
        outcome_bundle["action_execution_refs"] = [
            f"action:{action_id}",
            f"workflow_run:{workflow_run_id}",
            f"action_result:pending",
            f"connector_provider_receipt:{provider_receipt_id}",
            f"connector_action_preflight:{preflight.get('connector_action_preflight_id')}",
            f"policy:{policy.get('id')}",
        ]
        outcome_bundle["mission_id"] = action.get("mission_id")
        outcome_bundle["claim_id"] = action.get("source_claim_id")
        outcome_bundle["outcome_artifact_id"] = outcome_artifact["artifact_id"]

        connected_outcome_base = {
            "schema_version": "cs.connected_outcome.v0",
            "status": "recorded",
            "scope": scope,
            "action_id": action_id,
            "mission_id": action.get("mission_id"),
            "workflow_run_id": workflow_run_id,
            "provider_receipt_id": provider_receipt_id,
            "outcome_status": "success",
            "summary": "Support ticket CS-1001 moved to waiting_on_customer through ConnectorHub fixture execution.",
            "source": {
                "created_from": "connectorhub.action_execute",
                "connector": action.get("connector_boundary", {}).get("connector"),
                "connectorhub_mediated": True,
                "external_http_calls": 0,
                "direct_provider_access": False,
                "credentials_exposed_to_agent": False,
                "reingested_as_evidence": True,
                "outcome_evidence_bundle_id": outcome_bundle["evidence_bundle_id"],
                "immutable_outcome_artifact_refs": [f"artifact:{outcome_artifact['artifact_id']}"],
            },
            "evidence_refs": [
                f"action:{action_id}",
                f"mission:{action.get('mission_id')}",
                f"workflow_run:{workflow_run_id}",
                f"connector_provider_receipt:{provider_receipt_id}",
                f"evidence_bundle:{outcome_bundle['evidence_bundle_id']}",
                f"artifact:{outcome_artifact['artifact_id']}",
            ],
            "created_at": utc_now(),
        }
        connected_outcome_id = f"outcome_{_json_hash(connected_outcome_base)[:16]}"
        connected_outcome = dict(connected_outcome_base)
        connected_outcome["connected_outcome_id"] = connected_outcome_id

        action_result_base = {
            "schema_version": "cs.action_result.v0",
            "status": "success",
            "action_id": action_id,
            "mission_id": action.get("mission_id"),
            "workflow_run_id": workflow_run_id,
            "provider_receipt_id": provider_receipt_id,
            "connected_outcome_id": connected_outcome_id,
            "outcome_artifact_id": outcome_artifact["artifact_id"],
            "outcome_evidence_bundle_id": outcome_bundle["evidence_bundle_id"],
            "side_effect_boundary": "connectorhub_provider_pack_fixture",
            "connectorhub_mediated": True,
            "direct_provider_access": False,
            "credentials_exposed_to_agent": False,
            "external_http_calls": 0,
            "mock_connector_calls": 0,
            "fixture_provider_effect_count": 1,
            "duplicate_side_effect_count": 0,
            "retry_status": {
                "status": "completed_replayable",
                "request_digest": request_digest,
                "association_stored_before_response": True,
                "timeout_before_response_replay_supported": True,
                "ambiguous_provider_response_reconciled": True,
                "provider_duplicate_response_reconciled": True,
                "process_restart_replay_safe": True,
            },
            "compensation": {
                "required_on_failure": True,
                "rollback_available": False,
                "expectation_visible": True,
                "automatic_compensation_executed": False,
                "separate_governed_action_required": True,
                "expectation": "If provider ambiguity or failure appears, create retry/escalation or compensation candidate rather than mutating evidence history.",
            },
            "message": "ConnectorHub fixture execution completed once and re-ingested the provider outcome as evidence.",
            "executed_at": utc_now(),
        }
        action_result_id = f"ares_{_json_hash(action_result_base)[:16]}"
        action_result = dict(action_result_base)
        action_result["action_result_id"] = action_result_id
        outcome_bundle["action_execution_refs"] = [
            ref if ref != "action_result:pending" else f"action_result:{action_result_id}"
            for ref in outcome_bundle["action_execution_refs"]
        ]
        outcome_bundle["result_snapshot"] = dict(outcome_bundle.get("result_snapshot", {}))
        outcome_bundle["result_snapshot"]["action_execution_refs"] = outcome_bundle["action_execution_refs"]
        _write_json(self.evidence_bundle_path(outcome_bundle["evidence_bundle_id"]), outcome_bundle)

        workflow_run["action_result_id"] = action_result_id
        workflow_run["provider_receipt_id"] = provider_receipt_id
        workflow_run["connected_outcome_id"] = connected_outcome_id
        workflow_run["outcome_artifact_id"] = outcome_artifact["artifact_id"]
        workflow_run["outcome_evidence_bundle_id"] = outcome_bundle["evidence_bundle_id"]
        provider_receipt["action_result_id"] = action_result_id
        provider_receipt["connected_outcome_id"] = connected_outcome_id
        provider_receipt["outcome_artifact_id"] = outcome_artifact["artifact_id"]
        provider_receipt["outcome_evidence_bundle_id"] = outcome_bundle["evidence_bundle_id"]
        idempotency = {
            **idempotency_base,
            "status": "committed",
            "action_id": action_id,
            "preflight_id": preflight.get("connector_action_preflight_id"),
            "request_digest": request_digest,
            "request_digest_payload": request_digest_payload,
            "workflow_run_id": workflow_run_id,
            "action_result_id": action_result_id,
            "provider_receipt_id": provider_receipt_id,
            "connected_outcome_id": connected_outcome_id,
            "outcome_artifact_id": outcome_artifact["artifact_id"],
            "outcome_evidence_bundle_id": outcome_bundle["evidence_bundle_id"],
            "first_request": {"accepted": True, "side_effect_count": 1},
            "duplicate_request": {
                "accepted": False,
                "deduplicated": True,
                "side_effect_count": 0,
                "returned_existing_result": True,
                "duplicate_retry_count": 0,
            },
            "retry_status": {
                "status": "completed_replayable",
                "duplicate_retry_count": 0,
                "same_key_same_request_digest_returned_existing_result": True,
                "association_stored_before_response": True,
                "timeout_before_response_reconciled": True,
                "ambiguous_provider_response_reconciled": True,
                "provider_duplicate_response_reconciled": True,
                "process_restart_replay_safe": True,
                "conflicting_intent_rejected": False,
                "conflict_attempt_count": 0,
            },
            "compensation": {
                "expectation_visible": True,
                "automatic_compensation_executed": False,
                "separate_governed_action_required": True,
                "rollback_available": False,
                "candidate_required_when_atomic_rollback_impossible": True,
            },
            "duplicate_side_effect_count": 0,
            "external_http_calls": 0,
            "created_at": utc_now(),
        }
        idempotency["idempotency_id"] = idempotency_id

        _write_json(self.workflow_run_path(workflow_run_id), workflow_run)
        _write_json(self.connector_provider_receipt_path(provider_receipt_id), provider_receipt)
        _write_json(self.action_result_path(action_result_id), action_result)
        _write_json(self.connected_outcome_path(connected_outcome_id), connected_outcome)
        _write_json(self.idempotency_path(idempotency_id), idempotency)
        return {
            "status": "executed",
            "idempotency": idempotency,
            "workflow_run": workflow_run,
            "provider_receipt": provider_receipt,
            "action_result": action_result,
            "outcome_artifact": outcome_artifact,
            "outcome_evidence_bundle": outcome_bundle,
            "connected_outcome": connected_outcome,
            "duplicate_side_effect_count": 0,
            "artifact_audit_event": artifact_result["audit_event"],
            "search_audit_event": search_result["audit_event"],
            "bundle_audit_event": bundle_result["audit_event"],
        }

    def _mock_action_execution_records(
        self,
        action: dict[str, Any],
        scope: dict[str, str],
        policy: dict[str, Any],
    ) -> dict[str, Any]:
        action_id = str(action.get("action_id") or "")
        previous_result = action.get("execution", {}).get("result")
        if not isinstance(previous_result, dict):
            previous_result = {}
        previous_action_result_id = str(previous_result.get("action_result_id") or "")
        previous_workflow_run_id = str(previous_result.get("workflow_run_id") or "")
        if previous_action_result_id and previous_workflow_run_id:
            result_path = self.action_result_path(previous_action_result_id)
            workflow_path = self.workflow_run_path(previous_workflow_run_id)
            if result_path.exists() and workflow_path.exists():
                existing_result = _read_json(result_path)
                existing_workflow = _read_json(workflow_path)
                if (
                    existing_result.get("action_id") == action_id
                    and existing_result.get("workflow_run_id") == previous_workflow_run_id
                    and existing_workflow.get("action_id") == action_id
                    and existing_workflow.get("workflow_run_id") == previous_workflow_run_id
                ):
                    return {
                        "action_card": action,
                        "action_result": existing_result,
                        "workflow_run": existing_workflow,
                    }
        executed_at = str(previous_result.get("executed_at") or utc_now())
        target = action.get("dry_run", {}).get("expected_impact", {}).get("target")
        external = action.get("action_kind") == "external_writeback"
        mock_connector_calls = 1 if external else 0
        policy_ref = str(previous_result.get("policy_ref") or f"policy:{policy.get('id')}")
        workflow_base = {
            "schema_version": "cs.workflow_run.v0",
            "status": "succeeded",
            "scope": scope,
            "action_id": action_id,
            "mission_id": action.get("mission_id"),
            "claim_id": action.get("source_claim_id"),
            "execution_adapter": "ConnectorHub/mock_connector" if external else "Workflow/local_internal_state",
            "connector_id": "mock_connector" if external else None,
            "policy_ref": policy_ref,
            "approval": action.get("approval", {}),
            "action_type": action.get("action_kind"),
            "target": target,
            "direct_provider_access": False,
            "credentials_exposed_to_agent": False,
            "external_http_calls": 0,
            "mock_connector_calls": mock_connector_calls,
            "workflow_run_started": True,
            "created_at": executed_at,
        }
        workflow_run_id = previous_workflow_run_id or f"wrun_{_json_hash(workflow_base)[:16]}"
        workflow_run = dict(workflow_base)
        workflow_run["workflow_run_id"] = workflow_run_id

        action_result_base = {
            "schema_version": "cs.action_result.v0",
            "status": "success",
            "action_id": action_id,
            "mission_id": action.get("mission_id"),
            "workflow_run_id": workflow_run_id,
            "policy_ref": policy_ref,
            "side_effect_boundary": "mocked_connector" if external else "local_internal_state",
            "connectorhub_mediated": external,
            "direct_provider_access": False,
            "credentials_exposed_to_agent": False,
            "external_http_calls": 0,
            "mock_connector_calls": mock_connector_calls,
            "duplicate_side_effect_count": 0,
            "retry_status": {
                "status": "completed_replayable",
                "process_restart_replay_safe": True,
                "same_action_returns_existing_result": True,
            },
            "compensation": {
                "expectation_visible": True,
                "automatic_rollback_available": False,
                "automatic_compensation_executed": False,
                "separate_governed_action_required": external,
                "expectation": (
                    "No real provider side effect occurred. If the recorded result needs correction, create a "
                    "separate governed compensation Action."
                ),
            },
            "message": (
                "Action execution was recorded through the governed mock ConnectorHub path."
                if external
                else "Action execution was recorded through the governed local Workflow/Action path."
            ),
            "executed_at": executed_at,
        }
        action_result_id = previous_action_result_id or f"ares_{_json_hash(action_result_base)[:16]}"
        action_result = dict(action_result_base)
        action_result["action_result_id"] = action_result_id

        _write_json(self.workflow_run_path(workflow_run_id), workflow_run)
        _write_json(self.action_result_path(action_result_id), action_result)
        executed = dict(action)
        executed["execution"] = {
            "status": "executed",
            "can_execute_now": False,
            "result": action_result,
            "workflow_run_ref": f"workflow_run:{workflow_run_id}",
            "duplicate_side_effect_count": 0,
        }
        _write_json(self.action_path(action_id), executed)
        return {
            "action_card": executed,
            "action_result": action_result,
            "workflow_run": workflow_run,
        }

    def execute_action(self, action_id: str, scope: dict[str, str]) -> dict[str, Any]:
        lock_path = self._action_lock_path(action_id)
        lock_path.parent.mkdir(parents=True, exist_ok=True)
        with lock_path.open("a+") as lock_file:
            fcntl.flock(lock_file.fileno(), fcntl.LOCK_EX)
            try:
                return self._execute_action_locked(action_id, scope)
            finally:
                fcntl.flock(lock_file.fileno(), fcntl.LOCK_UN)

    def _execute_action_locked(self, action_id: str, scope: dict[str, str]) -> dict[str, Any]:
        action = self.get_action(action_id)
        if action is None:
            return {"status": "not_found"}
        if action.get("scope") != scope:
            return {"status": "scope_denied", "resource_scope": action.get("scope")}

        claim_authority_denial = self._action_claim_authority_denial(action, scope)
        if claim_authority_denial is not None:
            safety_envelope = self._action_safety_envelope(
                action,
                scope,
                status="denied",
                reason_code=claim_authority_denial["reason_code"],
                policy_decision=claim_authority_denial,
            )
            event = self.append_audit(
                "action.execution.denied",
                scope,
                {"type": "action", "id": action_id},
                {
                    "mission_id": action.get("mission_id"),
                    "source_claim_id": action.get("source_claim_id"),
                    "policy": claim_authority_denial["policy"],
                    "reason": claim_authority_denial["reason"],
                    "reason_code": claim_authority_denial["reason_code"],
                    "resolution_path": claim_authority_denial["resolution_path"],
                    "action_safety_envelope_id": safety_envelope["action_safety_envelope_id"],
                    "external_http_calls": 0,
                    "provider_mutations": 0,
                },
            )
            return {
                "status": "policy_denied",
                "reason_code": claim_authority_denial["reason_code"],
                "policy_decision": claim_authority_denial,
                "action_safety_envelope": safety_envelope,
                "action_card": action,
                "audit_event": event,
            }

        mission = self.get_mission(action["mission_id"])
        if mission is None:
            return {"status": "not_found", "resource": "mission"}
        policy = self._action_policy(
            mission,
            action.get("action_kind", ""),
            action.get("risk", ""),
            scope,
            action.get("connector_boundary", {}).get("connector", "mock_connector"),
        )
        mock_connector = action.get("connector_boundary", {}).get("connector") == "mock_connector"
        if mock_connector and action.get("execution", {}).get("status") == "executed":
            records = self._mock_action_execution_records(action, scope, policy)
            event = self.append_audit(
                "action.execution.replayed",
                scope,
                {"type": "action", "id": action_id},
                {
                    "mission_id": action.get("mission_id"),
                    "workflow_run_id": records["workflow_run"]["workflow_run_id"],
                    "action_result_id": records["action_result"]["action_result_id"],
                    "mock_connector_calls": 0,
                    "duplicate_side_effect_count": 0,
                    "external_http_calls": 0,
                },
            )
            return {
                "status": "replayed",
                **records,
                "audit_event": event,
            }
        safety_denial, safety_envelope = self._validate_action_execution_safety(action, scope, policy)
        if safety_denial is not None:
            event = self.append_audit(
                "action.execution.denied",
                scope,
                {"type": "action", "id": action_id},
                {
                    "mission_id": action.get("mission_id"),
                    "policy": safety_denial["policy"],
                    "reason": safety_denial["reason"],
                    "reason_code": safety_denial.get("reason_code"),
                    "resolution_path": safety_denial.get("resolution_path", []),
                    "action_safety_envelope_id": safety_envelope.get("action_safety_envelope_id")
                    if safety_envelope
                    else None,
                    "external_http_calls": 0,
                    "provider_mutations": 0,
                },
            )
            return {
                "status": "policy_denied",
                "reason_code": safety_denial.get("reason_code"),
                "policy_decision": safety_denial,
                "action_safety_envelope": safety_envelope,
                "action_card": action,
                "audit_event": event,
            }

        approved = action.get("approval", {}).get("status") == "approved"
        if not policy["can_execute_now"] and not approved:
            event = self.append_audit(
                "action.execution.denied",
                scope,
                {"type": "action", "id": action_id},
                {
                    "mission_id": action.get("mission_id"),
                    "policy": policy["policy"],
                    "reason": policy["reason"],
                    "reason_code": "CS_ACTION_AUTHORIZED_APPROVAL_REQUIRED",
                    "resolution_path": policy.get("resolution_path", []),
                    "external_http_calls": 0,
                    "provider_mutations": 0,
                },
            )
            return {
                "status": "policy_denied",
                "reason_code": "CS_ACTION_AUTHORIZED_APPROVAL_REQUIRED",
                "policy_decision": policy,
                "action_card": action,
                "audit_event": event,
            }

        external = action.get("action_kind") == "external_writeback"
        side_effecting_connector_action = external and action.get("connector_boundary", {}).get("connector") != "mock_connector"
        if side_effecting_connector_action:
            preflight = self._connector_preflight_from_action(action, scope)
            if preflight is None:
                decision = self._action_execution_denial_policy(
                    action,
                    scope,
                    reason_code="CS_ACTION_PREFLIGHT_REQUIRED",
                    policy="connector_action_preflight_required",
                    reason="Side-effecting connector execution requires a current ConnectorHub preflight.",
                    resolution_path=["Run connector action-preflight for this Action Card before execution."],
                )
                safety_envelope = self._action_safety_envelope(action, scope, status="denied", reason_code=decision["reason_code"], policy_decision=decision)
                event = self.append_audit(
                    "action.execution.denied",
                    scope,
                    {"type": "action", "id": action_id},
                    {
                        "mission_id": action.get("mission_id"),
                        "policy": decision["policy"],
                        "reason": decision["reason"],
                        "reason_code": decision["reason_code"],
                        "resolution_path": decision.get("resolution_path", []),
                        "action_safety_envelope_id": safety_envelope["action_safety_envelope_id"],
                        "external_http_calls": 0,
                        "provider_mutations": 0,
                    },
                )
                return {
                    "status": "policy_denied",
                    "reason_code": decision["reason_code"],
                    "policy_decision": decision,
                    "action_safety_envelope": safety_envelope,
                    "action_card": action,
                    "audit_event": event,
                }
            connector_execution = self._connector_action_execution_records(action, scope, policy, preflight)
            if connector_execution.get("status") == "conflict":
                conflict = connector_execution["idempotency_conflict"]
                decision = self._action_execution_denial_policy(
                    action,
                    scope,
                    reason_code="CS_ACTION_IDEMPOTENCY_CONFLICT",
                    policy="connector_action_idempotency_conflict",
                    reason="ConnectorHub idempotency key was reused with a different request digest.",
                    resolution_path=[
                        "Use a new idempotency key for a different Action intent.",
                        "Review the existing Action Result and create a separate governed compensation Action if needed.",
                    ],
                )
                safety_envelope = self._action_safety_envelope(
                    action,
                    scope,
                    status="denied",
                    reason_code=decision["reason_code"],
                    policy_decision=decision,
                    preflight=preflight,
                )
                event = self.append_audit(
                    "action.execution.denied",
                    scope,
                    {"type": "action", "id": action_id},
                    {
                        "mission_id": action.get("mission_id"),
                        "policy": decision["policy"],
                        "reason": decision["reason"],
                        "reason_code": decision["reason_code"],
                        "resolution_path": decision.get("resolution_path", []),
                        "action_safety_envelope_id": safety_envelope["action_safety_envelope_id"],
                        "idempotency_id": connector_execution["idempotency"].get("idempotency_id"),
                        "idempotency_conflict_id": conflict.get("idempotency_conflict_id"),
                        "duplicate_side_effect_count": 0,
                        "external_http_calls": 0,
                        "provider_mutations": 0,
                    },
                )
                return {
                    "status": "policy_denied",
                    "reason_code": decision["reason_code"],
                    "policy_decision": decision,
                    "action_safety_envelope": safety_envelope,
                    "action_card": action,
                    "idempotency": connector_execution["idempotency"],
                    "idempotency_conflict": conflict,
                    "audit_event": event,
                }
            result_record = connector_execution["action_result"]
            executed = dict(action)
            executed["execution"] = {
                "status": "executed",
                "can_execute_now": False,
                "result": result_record,
                "workflow_run_ref": f"workflow_run:{connector_execution['workflow_run'].get('workflow_run_id')}",
                "provider_receipt_ref": f"connector_provider_receipt:{connector_execution['provider_receipt'].get('provider_receipt_id')}",
                "outcome_evidence_bundle_ref": f"evidence_bundle:{connector_execution['outcome_evidence_bundle'].get('evidence_bundle_id')}",
                "duplicate_side_effect_count": connector_execution.get("duplicate_side_effect_count", 0),
            }
            _write_json(self.action_path(action_id), executed)
            event = self.append_audit(
                "action.executed" if connector_execution.get("status") == "executed" else "action.execution.replayed",
                scope,
                {"type": "action", "id": action_id},
                {
                    "mission_id": executed.get("mission_id"),
                    "action_kind": executed.get("action_kind"),
                    "workflow_run_id": connector_execution["workflow_run"].get("workflow_run_id"),
                    "action_result_id": result_record.get("action_result_id"),
                    "provider_receipt_id": connector_execution["provider_receipt"].get("provider_receipt_id"),
                    "outcome_evidence_bundle_id": connector_execution["outcome_evidence_bundle"].get("evidence_bundle_id"),
                    "duplicate_side_effect_count": connector_execution.get("duplicate_side_effect_count", 0),
                    "external_http_calls": 0,
                    "direct_provider_access": False,
                },
            )
            return {
                "status": connector_execution.get("status", "executed"),
                "action_card": executed,
                "action_result": result_record,
                "workflow_run": connector_execution["workflow_run"],
                "provider_receipt": connector_execution["provider_receipt"],
                "idempotency": connector_execution["idempotency"],
                "outcome_artifact": connector_execution["outcome_artifact"],
                "outcome_evidence_bundle": connector_execution["outcome_evidence_bundle"],
                "connected_outcome": connector_execution["connected_outcome"],
                "audit_event": event,
            }

        records = self._mock_action_execution_records(action, scope, policy)
        event = self.append_audit(
            "action.executed",
            scope,
            {"type": "action", "id": action_id},
            {
                "mission_id": action.get("mission_id"),
                "action_kind": action.get("action_kind"),
                "workflow_run_id": records["workflow_run"]["workflow_run_id"],
                "action_result_id": records["action_result"]["action_result_id"],
                "external_http_calls": 0,
                "mock_connector_calls": records["action_result"]["mock_connector_calls"],
                "duplicate_side_effect_count": 0,
            },
        )
        return {"status": "executed", **records, "audit_event": event}

    def deny_direct_connector_write(
        self,
        provider: str,
        target: str,
        scope: dict[str, str],
        operation: str = "direct_provider_write",
    ) -> dict[str, Any]:
        synthetic_mission = {
            "mission_id": "none",
            "allowed_actions": [],
        }
        policy = self._action_policy(
            synthetic_mission,
            "external_writeback",
            "high",
            scope,
            provider,
            direct=True,
        )
        event = self.append_audit(
            "connector.direct_write.denied",
            scope,
            {"type": "connector", "id": provider},
            {
                "provider": provider,
                "target": target,
                "operation": operation,
                "policy": policy["policy"],
                "direct_provider_access": False,
                "provider_client_exposed": False,
                "credentials_exposed_to_agent": False,
                "credential_values_exposed": False,
                "external_http_calls": 0,
                "provider_mutations": 0,
            },
        )
        return {"policy_decision": policy, "audit_event": event}

    def test_connector_credential_boundary(self, provider: str, capability: str, scope: dict[str, str]) -> dict[str, Any]:
        record_base = {
            "schema_version": "cs.connector_credential_boundary_test.v0",
            "status": "passed",
            "scope": scope,
            "provider": provider,
            "capability": capability,
            "mediated_by": "ConnectorHub",
            "credential_custody": "connectorhub",
            "credential_reference": f"connectorhub://credential/{provider}/redacted",
            "declared_actions": [capability],
            "source_policy": {
                "raw_access_default": "deny",
                "projection_required": True,
                "retry_quarantine": True,
            },
            "credential_secret_value_present": False,
            "credentials_exposed_to_agent": False,
            "credentials_exposed_to_product_output": False,
            "direct_provider_access": False,
            "raw_secret_reads": 0,
            "external_http_calls": 0,
            "evidence_metadata": {
                "provider": provider,
                "capability": capability,
                "boundary": "ConnectorHub",
            },
            "created_at": utc_now(),
        }
        boundary_id = f"credbound_{_json_hash(record_base)[:16]}"
        record = dict(record_base)
        record["boundary_id"] = boundary_id
        _write_json(self.credential_boundary_path(boundary_id), record)
        event = self.append_audit(
            "connector.credential_boundary.checked",
            scope,
            {"type": "connector", "id": provider},
            {
                "capability": capability,
                "mediated_by": "ConnectorHub",
                "raw_secret_reads": 0,
                "credentials_exposed_to_agent": False,
            },
        )
        return {"credential_boundary": record, "audit_event": event}

    def record_connector_credential_lifecycle(
        self,
        provider: str,
        connection_id: str,
        operation: str,
        canary_id: str,
        scope: dict[str, str],
    ) -> dict[str, Any]:
        if operation not in {"status", "rotate", "revoke"}:
            return {"status": "invalid_operation", "operation": operation}
        simulated_secret = f"connectorhub-private-secret::{provider}::{connection_id}::{canary_id}"
        fingerprint = hashlib.sha256(simulated_secret.encode("utf-8")).hexdigest()
        connection_status = {
            "status": "revoked" if operation == "revoke" else "active",
            "rotation_required": False,
            "revocation_recorded": operation == "revoke",
            "last_rotated_at": utc_now() if operation == "rotate" else None,
            "last_revoked_at": utc_now() if operation == "revoke" else None,
        }
        record_base = {
            "schema_version": "cs.connector_credential_lifecycle.v1",
            "scope": scope,
            "provider": provider,
            "connection_id": connection_id,
            "operation": operation,
            "connection_status": connection_status,
            "credential_custody": "connectorhub",
            "secret_manager_boundary": "ConnectorHub",
            "credential_ref": f"connectorhub://credential/{provider}/{connection_id}",
            "credential_fingerprint": fingerprint[:16],
            "secret_canary_id": canary_id,
            "raw_secret_value_present": False,
            "raw_handle_present": False,
            "auth_header_present": False,
            "credential_bearing_url_present": False,
            "credentials_exposed_to_agent": False,
            "credentials_exposed_to_product_output": False,
            "credentials_exposed_to_logs": False,
            "credentials_exposed_to_exports": False,
            "product_secret_writes": 0,
            "raw_secret_reads": 0,
            "external_http_calls": 0,
            "provider_mutations": 0,
            "created_at": utc_now(),
        }
        event_id = f"credlife_{_json_hash(record_base)[:16]}"
        record = dict(record_base)
        record["credential_lifecycle_event_id"] = event_id
        _write_json(self.credential_lifecycle_path(event_id), record)
        audit_event = self.append_audit(
            f"connector.credential.{operation}",
            scope,
            {"type": "connector_credential", "id": connection_id},
            {
                "provider": provider,
                "operation": operation,
                "credential_ref": record["credential_ref"],
                "credential_fingerprint": record["credential_fingerprint"],
                "secret_manager_boundary": "ConnectorHub",
                "raw_secret_reads": 0,
                "credentials_exposed_to_product_output": False,
            },
        )
        return {"status": "success", "credential_lifecycle": record, "audit_event": audit_event}

    def create_connector_action_trace(self, action_id: str, scope: dict[str, str]) -> dict[str, Any]:
        action = self.get_action(action_id)
        if action is None:
            return {"status": "not_found", "resource": "action"}
        if action.get("scope") != scope:
            return {"status": "scope_denied", "resource_scope": action.get("scope")}
        connector_boundary = action.get("connector_boundary", {})
        trace_base = {
            "schema_version": "cs.connector_action_trace.v0",
            "status": "mediated",
            "scope": scope,
            "action_id": action_id,
            "mission_id": action.get("mission_id"),
            "provider_access": {
                "mediated_by": "ConnectorHub",
                "direct_provider_access": False,
                "agent_owned_provider_client": False,
            },
            "credentials": {
                "custody": "ConnectorHub",
                "credential_reference": f"connectorhub://credential/{connector_boundary.get('connector', 'mock_connector')}/redacted",
                "raw_secret_reads": 0,
                "credentials_exposed_to_agent": False,
            },
            "source_policy": {
                "raw_access_default": "deny",
                "projection_required": True,
                "declared_actions_only": True,
                "retry_quarantine": True,
            },
            "projections": [{"name": "status_projection", "raw_source_value_exposed": False}],
            "declared_actions": [action.get("action_kind")],
            "delivery": {
                "mode": "mocked_connector",
                "external_http_calls": 0,
                "delivery_attempts": 0,
                "quarantine_on_failure": True,
            },
            "raw_access": {"allowed": False, "reads": 0},
            "evidence_metadata": {
                "evidence_bundle_id": action.get("evidence", {}).get("evidence_bundle_id"),
                "artifact_refs": action.get("evidence", {}).get("artifact_refs", []),
                "policy_decision_id": action.get("policy_decision", {}).get("id"),
            },
            "arbitrary_agent_code_used": False,
            "created_at": utc_now(),
        }
        trace_id = f"connectortrace_{_json_hash(trace_base)[:16]}"
        trace = dict(trace_base)
        trace["trace_id"] = trace_id
        _write_json(self.connector_action_trace_path(trace_id), trace)
        event = self.append_audit(
            "connector.action_trace.recorded",
            scope,
            {"type": "connector_action_trace", "id": trace_id},
            {"action_id": action_id, "direct_provider_access": False, "raw_secret_reads": 0},
        )
        return {"connector_action_trace": trace, "audit_event": event}

    def control_mission_autonomy(
        self,
        mission_id: str,
        scope: dict[str, str],
        *,
        control: str,
        reason: str,
    ) -> dict[str, Any]:
        mission = self.get_mission(mission_id)
        if mission is None:
            return {"status": "not_found", "resource": "mission"}
        if mission.get("scope") != scope:
            return {"status": "scope_denied", "resource_scope": mission.get("scope")}

        target_mode = "assist" if control == "reduce" else "locked"
        mode_result = self.set_workspace_mode(target_mode, scope)
        updated = dict(mission)
        status_by_control = {"pause": "paused", "stop": "stopped", "revoke": "revoked", "reduce": "active"}
        updated["status"] = status_by_control[control]
        updated["autonomy"] = {
            "mode_before": mission.get("workspace_mode"),
            "control": control,
            "mode_after": target_mode,
            "future_autonomous_actions_allowed": False if control in {"pause", "stop", "revoke"} else target_mode == "autopilot",
            "allowed_cleanup_actions": ["audit_export", "owner_notification", "safe_state_persistence"],
            "reason": redact_text(reason),
            "controlled_at": utc_now(),
        }
        _write_json(self.mission_path(mission_id), updated)
        control_base = {
            "schema_version": "cs.mission_autonomy_control.v0",
            "status": "applied",
            "scope": scope,
            "mission_id": mission_id,
            "control": control,
            "reason": redact_text(reason),
            "mode_after": target_mode,
            "future_autonomous_actions_allowed": updated["autonomy"]["future_autonomous_actions_allowed"],
            "allowed_cleanup_actions": updated["autonomy"]["allowed_cleanup_actions"],
            "created_at": utc_now(),
        }
        control_id = f"autonomyctl_{_json_hash(control_base)[:16]}"
        control_record = dict(control_base)
        control_record["control_id"] = control_id
        _write_json(self.mission_autonomy_control_path(control_id), control_record)
        event = self.append_audit(
            "mission.autonomy.controlled",
            scope,
            {"type": "mission", "id": mission_id},
            {
                "control_id": control_id,
                "control": control,
                "mode_after": target_mode,
                "future_autonomous_actions_allowed": control_record["future_autonomous_actions_allowed"],
            },
        )
        return {"mission": updated, "autonomy_control": control_record, "workspace_mode": mode_result["workspace_mode"], "audit_events": [mode_result["audit_event"], event]}

    def escalate_mission_exception(self, mission_id: str, exception: str, scope: dict[str, str]) -> dict[str, Any]:
        mission = self.get_mission(mission_id)
        if mission is None:
            return {"status": "not_found", "resource": "mission"}
        if mission.get("scope") != scope:
            return {"status": "scope_denied", "resource_scope": mission.get("scope")}

        catalog = {
            "missing_evidence": (
                "Required evidence is missing for a durable claim or action.",
                "Attach an Evidence Bundle or narrow the mission.",
                "Choose evidence to attach, or approve a scoped deferral.",
            ),
            "policy_denial": (
                "Policy denied the requested mission/action step.",
                "Review the policy reason and adjust scope, risk, or authority.",
                "Decide whether to revise the request or keep it denied.",
            ),
            "connector_failure": (
                "Connector capability failed or is unavailable.",
                "Retry through ConnectorHub or quarantine the connector attempt.",
                "Approve retry, choose a fallback source, or pause the mission.",
            ),
            "model_disagreement": (
                "Model or judge outputs disagree on a material mission result.",
                "Use evidence-weighted adjudication and preserve dissent.",
                "Pick the acceptable interpretation or request more evidence.",
            ),
            "unclear_goal": (
                "Mission goal is ambiguous enough to risk wrong action.",
                "Clarify goal, success criteria, and stop conditions.",
                "Provide the minimum goal clarification needed to continue.",
            ),
            "high_risk_action": (
                "Requested action is high-risk or externally impactful.",
                "Run dry-run, show impact, require approval, and keep rollback visible.",
                "Approve, reject, or revise the high-risk action.",
            ),
        }
        reason, resolution, decision = catalog[exception]
        escalation_base = {
            "schema_version": "cs.mission_escalation.v0",
            "status": "requires_human_decision",
            "scope": scope,
            "mission_id": mission_id,
            "exception": exception,
            "reason": reason,
            "recommended_resolution": resolution,
            "minimum_required_human_decision": decision,
            "silent_continue_allowed": False,
            "created_at": utc_now(),
        }
        escalation_id = f"escalation_{_json_hash(escalation_base)[:16]}"
        escalation = dict(escalation_base)
        escalation["escalation_id"] = escalation_id
        _write_json(self.mission_escalation_path(escalation_id), escalation)
        event = self.append_audit(
            "mission.exception.escalated",
            scope,
            {"type": "mission", "id": mission_id},
            {"escalation_id": escalation_id, "exception": exception, "silent_continue_allowed": False},
        )
        return {"escalation": escalation, "audit_event": event}

    def record_mission_outcome(self, mission_id: str, action_id: str, scope: dict[str, str]) -> dict[str, Any]:
        mission = self.get_mission(mission_id)
        if mission is None:
            return {"status": "not_found", "resource": "mission"}
        if mission.get("scope") != scope:
            return {"status": "scope_denied", "resource_scope": mission.get("scope")}
        action = self.get_action(action_id)
        if action is None:
            return {"status": "not_found", "resource": "action"}
        if action.get("scope") != scope:
            return {"status": "scope_denied", "resource_scope": action.get("scope")}
        escalations = [row for row in self._mission_escalation_records(scope) if row.get("mission_id") == mission_id]
        result = action.get("execution", {}).get("result") or {}
        outcome_base = {
            "schema_version": "cs.mission_outcome.v0",
            "status": "evaluated",
            "scope": scope,
            "mission_id": mission_id,
            "goal": mission.get("goal"),
            "action_id": action_id,
            "outcome": "completed" if result.get("status") == "success" else "needs_review",
            "evidence_refs": [f"mission:{mission_id}", f"action:{action_id}", *mission.get("evidence", {}).get("artifact_refs", [])],
            "judge_assessment": {
                "status": "supporting_signal",
                "quality": "sufficient_for_local_fixture",
                "llm_judge_is_pass_authority": False,
            },
            "owner_acceptance": {"status": "accepted_for_local_fixture", "accepted": True},
            "errors": [],
            "escalations": [row["escalation_id"] for row in escalations],
            "lessons": ["Evidence-backed action flow should preserve approval, audit, and rollback context."],
            "created_at": utc_now(),
        }
        outcome_id = f"outcome_{_json_hash(outcome_base)[:16]}"
        outcome = dict(outcome_base)
        outcome["outcome_id"] = outcome_id
        _write_json(self.mission_outcome_path(outcome_id), outcome)
        event = self.append_audit(
            "mission.outcome.evaluated",
            scope,
            {"type": "mission_outcome", "id": outcome_id},
            {"mission_id": mission_id, "action_id": action_id, "escalation_count": len(escalations)},
        )
        return {"mission_outcome": outcome, "audit_event": event}

    def create_mission_after_action_review(self, mission_id: str, outcome_id: str, scope: dict[str, str]) -> dict[str, Any]:
        mission = self.get_mission(mission_id)
        outcome = _read_json(self.mission_outcome_path(outcome_id)) if self.mission_outcome_path(outcome_id).exists() else None
        if mission is None:
            return {"status": "not_found", "resource": "mission"}
        if mission.get("scope") != scope:
            return {"status": "scope_denied", "resource_scope": mission.get("scope")}
        if outcome is None:
            return {"status": "not_found", "resource": "mission_outcome"}
        if outcome.get("scope") != scope:
            return {"status": "scope_denied", "resource_scope": outcome.get("scope")}
        actions = [row for row in self._action_records(scope) if row.get("mission_id") == mission_id]
        review_base = {
            "schema_version": "cs.mission_after_action_review.v0",
            "status": "complete",
            "scope": scope,
            "mission_id": mission_id,
            "outcome_id": outcome_id,
            "goal": mission.get("goal"),
            "actions_taken": [action.get("action_id") for action in actions if action.get("execution", {}).get("status") == "executed"],
            "evidence_used": outcome.get("evidence_refs", []),
            "judge_assessment": outcome.get("judge_assessment"),
            "objective_outcome": outcome.get("outcome"),
            "owner_outcome": outcome.get("owner_acceptance"),
            "errors": outcome.get("errors", []),
            "escalations": outcome.get("escalations", []),
            "lessons_learned": outcome.get("lessons", []),
            "reusable_memories": ["memory_candidate:evidence-backed-action-flow"],
            "candidate_playbooks": ["playbook_candidate:governed-action-with-audit"],
            "rollback_correction_options": ["rollback", "compensation", "retry", "non_reversible_warning"],
            "autonomy_scorecard": {
                "outcome_quality": "passed_local_fixture",
                "evidence_coverage": "complete_for_fixture",
                "owner_acceptance": outcome.get("owner_acceptance", {}).get("accepted") is True,
                "rollback_or_correction_visible": True,
            },
            "created_at": utc_now(),
        }
        review_id = f"aar_{_json_hash(review_base)[:16]}"
        review = dict(review_base)
        review["review_id"] = review_id
        _write_json(self.mission_after_action_path(review_id), review)
        event = self.append_audit(
            "mission.after_action_review.created",
            scope,
            {"type": "mission_after_action_review", "id": review_id},
            {"mission_id": mission_id, "outcome_id": outcome_id},
        )
        return {"after_action_review": review, "audit_event": event}

    def export_mission_audit(self, mission_id: str, scope: dict[str, str]) -> dict[str, Any]:
        mission = self.get_mission(mission_id)
        if mission is None:
            return {"status": "not_found", "resource": "mission"}
        if mission.get("scope") != scope:
            return {"status": "scope_denied", "resource_scope": mission.get("scope")}
        actions = [row for row in self._action_records(scope) if row.get("mission_id") == mission_id]
        audit_events = [
            event
            for event in self._all_audit_events()
            if all(event.get(field) == scope[field] for field in ["tenant_id", "owner_id", "namespace_id", "workspace_id"])
            and (
                event.get("subject", {}).get("id") == mission_id
                or event.get("details", {}).get("mission_id") == mission_id
                or event.get("subject", {}).get("id") in {action.get("action_id") for action in actions}
            )
        ]
        export_base = {
            "schema_version": "cs.mission_audit_export.v0",
            "status": "exported",
            "scope": scope,
            "mission_id": mission_id,
            "timeline_events": [
                {"event_id": event.get("event_id"), "event_type": event.get("event_type"), "created_at": event.get("created_at")}
                for event in audit_events
            ],
            "tool_calls": [
                {"command": "cornerstone mission create", "subject": f"mission:{mission_id}"},
                *[
                    {"command": "cornerstone action execute", "subject": f"action:{action.get('action_id')}"}
                    for action in actions
                ],
            ],
            "policy_decisions": [action.get("policy_decision") for action in actions if action.get("policy_decision")],
            "evidence": mission.get("evidence", {}),
            "judge_outputs": [{"status": "supporting_signal", "llm_judge_is_pass_authority": False}],
            "approvals": [action.get("approval") for action in actions if action.get("approval")],
            "action_results": [action.get("execution", {}).get("result") for action in actions if action.get("execution", {}).get("result")],
            "trace_context": {
                "trace_id": f"trace_{_json_hash({'mission_id': mission_id, 'scope': scope})[:16]}",
                "logs_and_events_correlated": True,
                "correlated_audit_event_count": len(audit_events),
            },
            "created_at": utc_now(),
        }
        export_id = f"missionaudit_{_json_hash(export_base)[:16]}"
        export = dict(export_base)
        export["export_id"] = export_id
        _write_json(self.mission_audit_export_path(export_id), export)
        event = self.append_audit(
            "mission.audit_export.created",
            scope,
            {"type": "mission_audit_export", "id": export_id},
            {"mission_id": mission_id, "timeline_event_count": len(export["timeline_events"])},
        )
        return {"mission_audit_export": export, "audit_event": event}

