    def operator_status_report(self, scope: dict[str, str]) -> dict[str, Any]:
        audit_lines = self._audit_snapshot_lines()
        audit = self._verify_audit_lines(audit_lines)
        event_types = [json.loads(line).get("event_type") for line in audit_lines if line.strip()]
        status_base = {
            "schema_version": "cs.operator_status_report.v0",
            "status": "ready",
            "scope": scope,
            "signals": {
                "ingestion": {"status": "ok", "artifact_count": len(self._artifact_records(scope))},
                "search": {"status": "ok"},
                "model_routing": {"status": "ok", "route_count": len(self._brain_route_records(scope))},
                "workflow_execution": {"status": "ok", "action_count": len(self._action_records(scope))},
                "connector_health": {"status": "ok", "mocked": True},
                "policy_denials": {"status": "visible", "count": sum(1 for event in event_types if "denied" in str(event))},
                "audit_integrity": {"status": audit.get("status"), "event_count": audit.get("event_count", 0)},
                "queue_retries": {"status": "ok", "retry_count": 0, "quarantine_count": 0},
                "failed_missions": {"status": "visible", "count": 0},
            },
            "telemetry_signals": ["logs", "metrics", "traces"],
            "shared_context": scope_key(scope),
            "external_http_calls": 0,
            "created_at": utc_now(),
        }
        status_id = f"opsstatus_{_json_hash(status_base)[:16]}"
        record = dict(status_base)
        record["status_id"] = status_id
        _write_json(self.operator_status_path(status_id), record)
        event = self.append_audit(
            "operator.status.reported",
            scope,
            {"type": "operator_status", "id": status_id},
            {"audit_status": audit.get("status"), "signals": sorted(status_base["signals"])},
        )
        return {"operator_status": record, "audit_event": event}

    def validate_release_report(
        self,
        scenario_report_path: Path,
        verification_report_path: Path,
        scope: dict[str, str],
    ) -> dict[str, Any]:
        errors: list[str] = []
        scenario_data: dict[str, Any] = {}
        markdown = ""
        if not scenario_report_path.exists():
            errors.append("missing_scenario_report")
        else:
            try:
                scenario_data = json.loads(scenario_report_path.read_text())
            except ValueError:
                errors.append("invalid_scenario_report_json")
        if not verification_report_path.exists():
            errors.append("missing_verification_report")
        else:
            markdown = verification_report_path.read_text()

        scenario_rows = scenario_data.get("scenario_results", []) if isinstance(scenario_data, dict) else []
        required_markdown_sections = [
            "Frozen Goal",
            "Scenario Table",
            "Human Required",
            "Command Evidence",
            "Gaps And Risks",
        ]
        missing_sections = [section for section in required_markdown_sections if section not in markdown]
        ai_rows = [row for row in scenario_rows if row.get("owner", "AI") != "Human"]
        pass_rows = [row for row in ai_rows if row.get("status") == "PASS"]
        human_rows = [row for row in scenario_rows if row.get("owner", "AI") == "Human"]
        human_required = scenario_data.get("human_required", []) if isinstance(scenario_data, dict) else []
        no_unverified_pass_claim = (
            bool(scenario_rows)
            and len(pass_rows) == len(ai_rows)
            and all(row.get("status") == "HUMAN_REQUIRED" for row in human_rows)
            and scenario_data.get("summary", {}).get("blocking") == 0
            and "does not mark production" in markdown
        )
        if missing_sections:
            errors.append("missing_markdown_sections")
        if not no_unverified_pass_claim:
            errors.append("unverified_or_overbroad_claim")

        report_base = {
            "schema_version": "cs.release_report_validation.v0",
            "status": "passed" if not errors else "failed",
            "scope": scope,
            "scenario_report_path": str(scenario_report_path),
            "verification_report_path": str(verification_report_path),
            "scenario_count": len(scenario_rows),
            "pass_count": len(pass_rows),
            "blocking": scenario_data.get("summary", {}).get("blocking") if isinstance(scenario_data, dict) else None,
            "human_required_count": len(human_required),
            "required_sections": required_markdown_sections,
            "missing_sections": missing_sections,
            "no_implementation_claim_without_repo_evidence": no_unverified_pass_claim,
            "scenario_verification_remains_release_standard": not errors,
            "documented_target_distinguished_from_current_implementation": "does not mark production" in markdown,
            "errors": errors,
            "created_at": utc_now(),
        }
        report_id = f"relreport_{_json_hash(report_base)[:16]}"
        report = dict(report_base)
        report["report_id"] = report_id
        _write_json(self.release_report_path(report_id), report)
        event = self.append_audit(
            "release.report.validated",
            scope,
            {"type": "release_report", "id": report_id},
            {"status": report["status"], "scenario_count": len(scenario_rows), "errors": errors},
        )
        return {"release_report_validation": report, "audit_event": event}

    def _artifact_identity_for_ingest(
        self,
        checksum: str,
        size_bytes: int,
        scope: dict[str, str],
    ) -> tuple[str, dict[str, Any] | None, dict[str, Any] | None]:
        def record_identity_valid(record: dict[str, Any], artifact_id: str) -> bool:
            return bool(
                record.get("artifact_id") == artifact_id
                and record.get("checksum_sha256") == checksum
                and record.get("content_identity") == {"algorithm": "sha256", "value": checksum}
                and record.get("original_storage_ref") == f"sha256:{checksum}"
                and record.get("original_size_bytes") == size_bytes
                and record.get("scope") == scope
            )

        canonical_id = f"art_{checksum}"
        try:
            canonical = self._get_artifact_unchecked(canonical_id, scope)
        except (OSError, ValueError, TypeError, json.JSONDecodeError):
            return canonical_id, None, {
                "status": "integrity_failed",
                "reason": "canonical_artifact_record_unreadable",
                "artifact_id": canonical_id,
            }
        if canonical is not None:
            if not record_identity_valid(canonical, canonical_id):
                return canonical_id, None, {
                    "status": "integrity_failed",
                    "reason": "canonical_artifact_identity_mismatch",
                    "artifact_id": canonical_id,
                }
            return canonical_id, canonical, None

        legacy_id = f"art_{checksum[:16]}"
        try:
            legacy = self._get_artifact_unchecked(legacy_id, scope)
        except (OSError, ValueError, TypeError, json.JSONDecodeError):
            return legacy_id, None, {
                "status": "integrity_failed",
                "reason": "legacy_artifact_record_unreadable",
                "artifact_id": legacy_id,
            }
        if legacy is not None and legacy.get("checksum_sha256") == checksum:
            if not record_identity_valid(legacy, legacy_id):
                return legacy_id, None, {
                    "status": "integrity_failed",
                    "reason": "legacy_artifact_identity_mismatch",
                    "artifact_id": legacy_id,
                }
            return legacy_id, legacy, None
        return canonical_id, None, None

    def _artifact_lock_path(self, checksum: str, scope: dict[str, str]) -> Path:
        lock_key = sha256_bytes(f"{scope_key(scope)}:{checksum}".encode("utf-8"))
        return self.state_dir / "locks" / "artifacts" / f"{lock_key}.lock"

    def ingest_text_artifact(
        self,
        text: str,
        scope: dict[str, str],
        *,
        source_type: str,
        source_ref: str,
        trust: str = "untrusted",
    ) -> dict[str, Any]:
        checksum = sha256_bytes(text.encode("utf-8"))
        lock_path = self._artifact_lock_path(checksum, scope)
        lock_path.parent.mkdir(parents=True, exist_ok=True)
        with _artifact_thread_lock(lock_path):
            with lock_path.open("a+") as lock_file:
                fcntl.flock(lock_file.fileno(), fcntl.LOCK_EX)
                try:
                    return self._ingest_text_artifact_locked(
                        text,
                        scope,
                        source_type=source_type,
                        source_ref=source_ref,
                        trust=trust,
                    )
                finally:
                    fcntl.flock(lock_file.fileno(), fcntl.LOCK_UN)

    def _ingest_text_artifact_locked(
        self,
        text: str,
        scope: dict[str, str],
        *,
        source_type: str,
        source_ref: str,
        trust: str = "untrusted",
    ) -> dict[str, Any]:
        data = text.encode("utf-8")
        checksum = sha256_bytes(data)
        artifact_id, existing, identity_error = self._artifact_identity_for_ingest(checksum, len(data), scope)
        if identity_error is not None:
            return identity_error
        original_storage_ref = f"sha256:{checksum}"
        raw_text = data.decode("utf-8", errors="replace")
        untrusted_text_sources = {"user_paste", "conversation_turn"}
        effective_trust = "untrusted" if source_type in untrusted_text_sources else trust
        trust_forced_untrusted = effective_trust == "untrusted" and trust != "untrusted"
        blocked_attempts = detect_unsafe_instructions(raw_text) if effective_trust == "untrusted" else []
        safety = {
            "untrusted_evidence": effective_trust == "untrusted",
            "unsafe_instruction_detected": bool(blocked_attempts),
            "blocked_attempt_count": len(blocked_attempts),
            "blocked_attempts": blocked_attempts,
            "tool_calls_created": 0,
            "action_cards_created_from_untrusted_artifact": 0,
            "external_http_calls": 0,
            "authority_expanded": False,
        }
        original_path = self.original_dir / checksum
        original_storage_status = store_content_atomically(
            original_path,
            data,
            checksum_sha256=checksum,
        )

        if existing and existing.get("scope") == scope:
            updated = dict(existing)
            record_changed = False
            trust_downgraded = False
            existing_trust_was_stronger = bool(
                existing.get("trust_state") != "untrusted"
                or existing.get("safety", {}).get("untrusted_evidence") is not True
                or existing.get("safety", {}).get("unsafe_instruction_detected") != safety["unsafe_instruction_detected"]
            )
            source_changed = bool(
                existing.get("source", {}).get("type") != source_type
                or existing.get("source", {}).get("ref") != source_ref
            )
            if effective_trust == "untrusted" and (existing_trust_was_stronger or source_changed):
                source_history = list(updated.get("source_history", [])) if isinstance(updated.get("source_history"), list) else []
                if isinstance(updated.get("source"), dict):
                    source_history.append(updated["source"])
                source_observation = {
                    "type": source_type,
                    "ref": source_ref,
                    "ingested_at": utc_now(),
                }
                source_history.append(source_observation)
                updated["trust_state"] = "untrusted"
                updated["safety"] = safety
                updated["source_history"] = source_history[-8:]
                updated.setdefault("provenance", {}).setdefault("transformations", [])
                transformations = updated["provenance"]["transformations"]
                if "trust_forced_untrusted" not in transformations:
                    transformations.append("trust_forced_untrusted")
                # A duplicate observation must not hide the original source
                # classification. Rebind the primary source only when this
                # observation actually lowers trust; otherwise Search could
                # exclude a saved source merely because the same bytes later
                # appeared as a conversation turn.
                if existing_trust_was_stronger or source_type != "conversation_turn":
                    updated["source"] = source_observation
                    if "source_rebound_to_untrusted_text" not in transformations:
                        transformations.append("source_rebound_to_untrusted_text")
                trust_downgraded = existing_trust_was_stronger
                record_changed = True
            resolved_representation = self._resolved_derived_representation(updated)
            legacy_representation = bool(
                resolved_representation
                and resolved_representation[0].get("schema_version") == "cs.derived_representation.legacy.v1"
            )
            if resolved_representation is None or legacy_representation:
                redacted_text = redact_text(raw_text)
                updated["derived"] = self._create_derived_representation(
                    artifact_id=artifact_id,
                    artifact_checksum_sha256=checksum,
                    text=redacted_text,
                    redacted=redacted_text != raw_text,
                )
                transformations = updated.setdefault("provenance", {}).setdefault("transformations", [])
                transformation = (
                    "derived_representation_migrated"
                    if legacy_representation
                    else "derived_representation_repaired"
                )
                if transformation not in transformations:
                    transformations.append(transformation)
                record_changed = True
            if record_changed:
                _write_json(self.artifact_path(artifact_id, scope), updated)
                existing = updated
            event = self.append_audit(
                "artifact.deduplicated",
                scope,
                {"type": "artifact", "id": artifact_id},
                {
                    "checksum_sha256": checksum,
                    "original_storage_ref": original_storage_ref,
                    "source_type": source_type,
                    "effective_trust": effective_trust,
                    "trust_forced_untrusted": trust_forced_untrusted,
                    "trust_downgraded": trust_downgraded,
                    "unsafe_instruction_detected": safety["unsafe_instruction_detected"],
                    "original_storage_status": original_storage_status,
                },
            )
            return {
                "artifact": existing,
                "deduplicated": True,
                "audit_event": event,
                "trust_forced_untrusted": trust_forced_untrusted,
                "trust_downgraded": trust_downgraded,
            }

        now = utc_now()
        redacted_text = redact_text(raw_text)
        derived = self._create_derived_representation(
            artifact_id=artifact_id,
            artifact_checksum_sha256=checksum,
            text=redacted_text,
            redacted=redacted_text != raw_text,
        )
        transformations = ["hash_calculated", "original_preserved", "derived_text_created"]
        if trust_forced_untrusted:
            transformations.append("trust_forced_untrusted")
        record = {
            "schema_version": "cs.artifact.v0",
            "artifact_id": artifact_id,
            "checksum_sha256": checksum,
            "content_identity": {"algorithm": "sha256", "value": checksum},
            "original_storage_ref": original_storage_ref,
            "raw_original_access": {"policy": "owner_scope_required", "display": "controlled"},
            "original_size_bytes": len(data),
            "media_type": "text/plain",
            "trust_state": effective_trust,
            "safety": safety,
            "scope": scope,
            "source": {
                "type": source_type,
                "ref": source_ref,
                "ingested_at": now,
            },
            "derived": derived,
            "provenance": {
                "created_at": now,
                "lineage_from": None,
                "transformations": transformations,
            },
        }
        _write_json(self.artifact_path(artifact_id, scope), record)
        event = self.append_audit(
            "artifact.ingested",
            scope,
            {"type": "artifact", "id": artifact_id},
            {
                "checksum_sha256": checksum,
                "original_storage_ref": original_storage_ref,
                "source_type": source_type,
                "derived_status": "ready",
                "unsafe_instruction_detected": safety["unsafe_instruction_detected"],
                "effective_trust": effective_trust,
                "trust_forced_untrusted": trust_forced_untrusted,
                "derived_representation_id": derived.get("derived_representation_id"),
                "original_storage_status": original_storage_status,
            },
        )
        return {
            "artifact": record,
            "deduplicated": False,
            "audit_event": event,
            "trust_forced_untrusted": trust_forced_untrusted,
            "trust_downgraded": False,
        }

    def start_conversation(self, message: str, scope: dict[str, str]) -> dict[str, Any]:
        conversation_base = {
            "schema_version": "cs.conversation.v0",
            "scope": scope,
            "started_from": "natural_message",
            "pre_modeling_required": False,
            "required_setup": {
                "connector_setup": False,
                "model_provider_setup": False,
                "ontology_setup": False,
                "organization_policy_setup": False,
            },
            "created_at": utc_now(),
        }
        conversation_id = f"conv_{_json_hash({**conversation_base, 'message': message})[:16]}"
        artifact_result = self.ingest_text_artifact(
            message,
            scope,
            source_type="conversation_turn",
            source_ref=conversation_id,
            trust="untrusted",
        )
        if artifact_result.get("status") == "integrity_failed":
            return artifact_result
        artifact = artifact_result["artifact"]
        artifact_safety = artifact.get("safety", {}) if isinstance(artifact, dict) else {}
        unsafe_instruction_detected = artifact_safety.get("unsafe_instruction_detected") is True
        conversation_safety = {
            "untrusted_message": True,
            "source_artifact_id": artifact["artifact_id"],
            "unsafe_instruction_detected": unsafe_instruction_detected,
            "blocked_attempt_count": int(artifact_safety.get("blocked_attempt_count", 0) or 0),
            "blocked_attempts": list(artifact_safety.get("blocked_attempts", [])),
            "promotion_allowed": not unsafe_instruction_detected,
            "promotion_blocked_reason": "prompt_injection_blocked" if unsafe_instruction_detected else None,
            "tool_calls_created_from_unsafe_prompt": int(artifact_safety.get("tool_calls_created", 0) or 0),
            "action_cards_created_from_unsafe_prompt": int(artifact_safety.get("action_cards_created_from_untrusted_artifact", 0) or 0),
            "claim_promotions_created_from_unsafe_prompt": 0,
            "claim_approvals_created_from_unsafe_prompt": 0,
            "memory_approvals_created_from_unsafe_prompt": 0,
            "hidden_memory_writes_created_from_unsafe_prompt": 0,
            "action_executions_created_from_unsafe_prompt": 0,
            "policy_changes_created_from_unsafe_prompt": 0,
            "cross_workspace_reads_created_from_unsafe_prompt": 0,
            "unredacted_secret_leaks_created_from_unsafe_prompt": 0,
            "external_http_calls": int(artifact_safety.get("external_http_calls", 0) or 0),
            "direct_provider_access": False,
            "authority_expanded": False,
        }
        suggested_outputs = [
            {"type": "Mission Card", "mode": "optional_promotion", "forced": False},
            {"type": "Knowledge Capsule", "mode": "optional_promotion", "forced": False},
            {"type": "Claim", "mode": "optional_promotion", "forced": False},
            {"type": "Action Card", "mode": "optional_promotion", "forced": False},
            {"type": "Memory", "mode": "optional_promotion", "forced": False},
            {"type": "Playbook Candidate", "mode": "optional_promotion", "forced": False},
        ]
        if unsafe_instruction_detected:
            suggested_outputs = [
                {**item, "mode": "blocked_prompt_injection", "blocked_reason": "prompt_injection_blocked"}
                for item in suggested_outputs
            ]
        turn = {
            "turn_id": f"turn_{_json_hash({'conversation_id': conversation_id, 'role': 'user', 'message': message})[:16]}",
            "role": "user",
            "content": redact_text(message),
            "artifact_ref": f"artifact:{artifact['artifact_id']}",
            "safety": conversation_safety,
            "created_at": utc_now(),
        }
        conversation = dict(conversation_base)
        conversation.update(
            {
                "conversation_id": conversation_id,
                "turns": [turn],
                "source_artifact_id": artifact["artifact_id"],
                "safety": conversation_safety,
                "suggested_outputs": suggested_outputs,
                "user_can_continue_without_conversion": True,
            }
        )
        _write_json(self.conversation_path(conversation_id), conversation)
        event = self.append_audit(
            "conversation.started",
            scope,
            {"type": "conversation", "id": conversation_id},
            {
                "source_artifact_id": artifact["artifact_id"],
                "suggested_output_types": [item["type"] for item in conversation["suggested_outputs"]],
                "unsafe_instruction_detected": unsafe_instruction_detected,
                "promotion_allowed": conversation_safety["promotion_allowed"],
            },
        )
        return {
            "conversation": conversation,
            "artifact": artifact,
            "audit_events": [artifact_result["audit_event"], event],
        }

    def promote_conversation_to_claim(
        self,
        conversation_id: str,
        statement: str,
        evidence_bundle_id: str,
        scope: dict[str, str],
    ) -> dict[str, Any]:
        conversation = self.get_conversation(conversation_id)
        if conversation is None:
            return {"status": "not_found", "resource": "conversation"}
        if conversation.get("scope") != scope:
            return {"status": "scope_denied", "resource_scope": conversation.get("scope")}

        source_safety = self.conversation_source_safety(conversation, scope)
        if source_safety.get("unsafe_instruction_detected") is True:
            policy_decision = {
                "policy_decision_id": f"policy_{_json_hash({'conversation_id': conversation_id, 'evidence_bundle_id': evidence_bundle_id, 'reason': 'prompt_injection_blocked'})[:16]}",
                "decision": "deny",
                "reason": "prompt_injection_blocked",
                "applies_to": "conversation.promote",
                "tool_calls_created": 0,
                "action_cards_created": 0,
                "claim_promotions_created": 0,
                "memory_approvals_created": 0,
                "action_executions_created": 0,
                "policy_changes_created": 0,
                "external_http_calls": 0,
                "direct_provider_access": False,
                "cross_workspace_reads": 0,
                "unredacted_secret_leaks": 0,
                "authority_expanded": False,
            }
            event = self.append_audit(
                "conversation.promotion.denied",
                scope,
                {"type": "conversation", "id": conversation_id},
                {
                    "reason": "prompt_injection_blocked",
                    "policy_decision_id": policy_decision["policy_decision_id"],
                    "promoted_kind": "claim",
                    "evidence_bundle_id": evidence_bundle_id,
                    "source_artifact_id": conversation.get("source_artifact_id"),
                    "blocked_attempt_count": int(source_safety.get("blocked_attempt_count", 0) or 0),
                    **{
                        key: value
                        for key, value in policy_decision.items()
                        if key != "policy_decision_id" and key not in {"decision", "reason", "applies_to"}
                    },
                },
            )
            return {
                "status": "unsafe_source_denied",
                "conversation": conversation,
                "source_safety": source_safety,
                "policy_decision": policy_decision,
                "audit_events": [event],
            }

        result = self.create_claim_from_evidence_bundle(evidence_bundle_id, statement, scope)
        if result.get("status"):
            return result

        claim = dict(result["claim"])
        claim["source_conversation"] = {
            "conversation_id": conversation_id,
            "turn_refs": [f"conversation_turn:{turn['turn_id']}" for turn in conversation.get("turns", [])],
            "source_artifact_ref": f"artifact:{conversation.get('source_artifact_id')}",
        }
        claim["provenance"] = {
            "created_from": "conversation.promote",
            "source_conversation_id": conversation_id,
            "source_artifact_id": conversation.get("source_artifact_id"),
            "promoted_at": utc_now(),
        }
        _write_json(self.claim_path(claim["claim_id"]), claim)
        event = self.append_audit(
            "conversation.promoted",
            scope,
            {"type": "claim", "id": claim["claim_id"]},
            {
                "conversation_id": conversation_id,
                "evidence_bundle_id": evidence_bundle_id,
                "promoted_kind": "claim",
                "trust_state": claim.get("trust_state"),
            },
        )
        return {"claim": claim, "audit_events": [result["audit_event"], event]}

    def answer_conversation(
        self,
        conversation_id: str,
        question: str,
        scope: dict[str, str],
        *,
        search_result: dict[str, Any] | None = None,
        model_provider: str = DEFAULT_MODEL_PROVIDER,
        generation_model: str = DEFAULT_GENERATION_MODEL,
        embedding_model: str = DEFAULT_EMBEDDING_MODEL,
        ollama_base_url: str | None = None,
    ) -> dict[str, Any]:
        conversation = self.get_conversation(conversation_id)
        if conversation is None:
            return {"status": "not_found", "resource": "conversation"}
        if conversation.get("scope") != scope:
            return {"status": "scope_denied", "resource_scope": conversation.get("scope")}

        # The Ask turn is stored as an Artifact before this method runs. It is
        # conversation context, not independent evidence for its own answer.
        if search_result is None:
            search_result = self.search(question, excluded_source_types={"conversation_turn"}, **scope)
        snapshot = search_result["snapshot"]
        evidence_refs: list[str] = []
        meaningful_question_terms = {
            term
            for term in search_terms(question)
            if _meaningful_search_term(term) and term not in ANSWER_STOP_TERMS
        }
        matched_terms = {
            str(reason.get("matched_term") or reason.get("query_term") or reason.get("query")).lower()
            for result in snapshot.get("results", [])
            for reason in result.get("match_reasons", [])
            if isinstance(reason, dict)
        }
        supported_by_meaningful_match = bool(meaningful_question_terms & matched_terms)
        has_relevant_evidence = snapshot.get("result_count", 0) > 0 and supported_by_meaningful_match

        model_error = None
        model_output: dict[str, Any] | None = None
        complete_wording_projection: dict[str, Any] | None = None
        labeled_field_projection: dict[str, Any] | None = None
        allocation_citation_projection: dict[str, Any] | None = None
        chunks_result = {"status": "not_requested", "chunks": []}
        if model_provider == "ollama" and has_relevant_evidence:
            evidence_items, evidence_error = self._evidence_items_from_snapshot(snapshot, scope)
            if evidence_error is not None:
                model_error = str(evidence_error)
            elif evidence_items:
                chunks_result = self._build_evidence_chunks(
                    evidence_items,
                    scope,
                    query=question,
                    evidence_bundle_id=None,
                    evidence_revision_sha256=str(snapshot.get("result_revision_sha256") or ""),
                    model_provider=model_provider,
                    embedding_model=embedding_model,
                    ollama_base_url=ollama_base_url,
                    allow_boundary_overlap_backfill=True,
                )
                if chunks_result.get("status") == "success" and chunks_result.get("chunks"):
                    try:
                        model_output = _ollama_generate_json(
                            ollama_base_url,
                            model=generation_model,
                            prompt=self._answer_prompt(question, chunks_result["chunks"]),
                            json_schema=ANSWER_JSON_SCHEMA,
                        )
                        complete_wording_projection = (
                            _direct_complete_wording_answer_projection(
                                question,
                                list(chunks_result["chunks"]),
                            )
                        )
                        if complete_wording_projection is not None:
                            model_output["answer"] = complete_wording_projection[
                                "answer"
                            ]
                            model_output["citation_refs"] = list(
                                complete_wording_projection["citation_refs"]
                            )
                            model_output["insufficient_evidence"] = False
                            model_output.setdefault(
                                "_ollama_response_metadata",
                                {},
                            )["direct_complete_wording_projection"] = {
                                "validation_mode": complete_wording_projection[
                                    "validation_mode"
                                ],
                            }
                        else:
                            labeled_field_projection = (
                                _direct_labeled_date_source_projection(
                                    question,
                                    list(chunks_result["chunks"]),
                                )
                            )
                        if labeled_field_projection is not None:
                            model_output["answer"] = labeled_field_projection[
                                "answer"
                            ]
                            model_output["citation_refs"] = list(
                                labeled_field_projection["citation_refs"]
                            )
                            model_output["insufficient_evidence"] = False
                            model_output.setdefault(
                                "_ollama_response_metadata",
                                {},
                            )["direct_labeled_field_projection"] = {
                                "identifiers": labeled_field_projection[
                                    "identifiers"
                                ],
                                "validation_mode": labeled_field_projection[
                                    "validation_mode"
                                ],
                            }
                        else:
                            allocation_citation_projection = (
                                _direct_allocation_citation_projection(
                                    question,
                                    str(model_output.get("answer") or ""),
                                    list(chunks_result["chunks"]),
                                )
                            )
                            if allocation_citation_projection is not None:
                                model_output["citation_refs"] = list(
                                    allocation_citation_projection["citation_refs"]
                                )
                                model_output.setdefault(
                                    "_ollama_response_metadata",
                                    {},
                                )["direct_allocation_citation_projection"] = {
                                    "bindings": allocation_citation_projection[
                                        "bindings"
                                    ],
                                    "validation_mode": allocation_citation_projection[
                                        "validation_mode"
                                    ],
                                }
                    except RuntimeError as error:
                        model_error = str(error)
                else:
                    model_error = str(chunks_result.get("error") or "No evidence chunks available for model answer.")
            else:
                model_error = "No evidence items available for model answer."

        citation_refs: list[str] = []
        citation_check_refs: list[str] = []
        prompt_boundary = self._prompt_boundary(
            list(chunks_result.get("chunks", [])),
            model_provider=model_provider,
            generation_model=generation_model if model_provider == "ollama" else None,
            embedding_model=embedding_model if model_provider == "ollama" else None,
        )

        if model_provider == "ollama" and model_output is not None:
            chunks = list(chunks_result.get("chunks", []))
            allowed_refs = {f"evidence_chunk:{chunk['evidence_chunk_id']}" for chunk in chunks}
            raw_refs = model_output.get("citation_refs") if isinstance(model_output.get("citation_refs"), list) else []
            # The checker must receive model-claimed refs verbatim enough to
            # detect fabricated or malformed citations; do not pre-filter them
            # to the retrieval allow-list.
            citation_refs = sorted({str(ref) for ref in raw_refs if str(ref).strip()})
            citation_check = self._citation_check(
                output_kind="conversation_answer",
                citation_refs=citation_refs,
                scope=scope,
                allowed_refs=allowed_refs,
            )
            citation_check_refs = [f"citation_check:{citation_check['citation_check_id']}"]
            insufficient_requested = bool(model_output.get("insufficient_evidence"))
            answer_text = str(model_output.get("answer") or "").strip()
            cited_chunks = [
                self.get_evidence_chunk(ref.split(":", 1)[1])
                for ref in citation_refs
                if ref.startswith("evidence_chunk:") and ref in allowed_refs
            ]
            cited_source_texts = [
                str(chunk.get("text") or "")
                for chunk in cited_chunks
                if isinstance(chunk, dict)
            ]
            statement_anchor_check = _statement_source_anchor(
                answer_text,
                cited_source_texts,
                allow_cross_source=True,
            )
            model_answer_anchor_check = deepcopy(statement_anchor_check)
            relationship_supported = _answer_relationship_supported(
                question,
                answer_text,
                cited_source_texts,
            )
            model_answer_anchor_check["question_relationship_supported"] = (
                relationship_supported
            )
            direct_labeled_field_projection_supported = bool(
                labeled_field_projection
                and citation_check.get("status") == "passed"
                and citation_refs
            )
            direct_allocation_citation_projection_supported = bool(
                allocation_citation_projection
                and citation_check.get("status") == "passed"
                and citation_refs
            )
            direct_complete_wording_projection_supported = bool(
                complete_wording_projection
                and citation_check.get("status") == "passed"
                and citation_refs
            )
            if direct_complete_wording_projection_supported:
                relationship_supported = True
            if direct_labeled_field_projection_supported:
                # The projection has already bound the literal labeled value
                # to every explicit contract identifier within one Artifact.
                # Treat that artifact-bound relation as the effective Ask
                # relationship instead of asking the generic scalar matcher to
                # infer identifiers split across adjacent quoted windows.
                relationship_supported = True
            event_projection = (
                None
                if direct_labeled_field_projection_supported
                else _direct_event_answer_projection(
                    question,
                    answer_text,
                    cited_source_texts,
                )
            )
            if event_projection:
                answer_text = event_projection
                statement_anchor_check = _statement_source_anchor(
                    answer_text,
                    cited_source_texts,
                    allow_cross_source=True,
                )
                relationship_supported = _answer_relationship_supported(
                    question,
                    answer_text,
                    cited_source_texts,
                )
            scalar_projection = None
            if (
                not direct_labeled_field_projection_supported
                and (
                    statement_anchor_check.get("status") != "passed"
                    or not relationship_supported
                )
            ):
                scalar_projection = _direct_scalar_answer_projection(
                    question,
                    answer_text,
                    cited_source_texts,
                )
                if scalar_projection:
                    answer_text = scalar_projection
                    statement_anchor_check = _statement_source_anchor(
                        answer_text,
                        cited_source_texts,
                        allow_cross_source=True,
                    )
                    relationship_supported = _answer_relationship_supported(
                        question,
                        answer_text,
                        cited_source_texts,
                    )
            projected_source_anchor_check = deepcopy(statement_anchor_check)
            raw_anchor_status = str(model_answer_anchor_check.get("status") or "failed")
            direct_scalar_projection_supported = bool(
                scalar_projection and relationship_supported
            )
            direct_event_projection_supported = bool(
                event_projection
                and statement_anchor_check.get("status") == "passed"
                and relationship_supported
            )
            statement_anchor_check["raw_anchor_status"] = raw_anchor_status
            statement_anchor_check["raw_source_anchor_check"] = model_answer_anchor_check
            if scalar_projection:
                statement_anchor_check["projected_source_anchor_check"] = (
                    projected_source_anchor_check
                )
            elif event_projection:
                statement_anchor_check["projected_source_anchor_check"] = (
                    projected_source_anchor_check
                )
            statement_anchor_check["question_relationship_supported"] = relationship_supported
            statement_anchor_check["direct_scalar_projection_supported"] = (
                direct_scalar_projection_supported
            )
            statement_anchor_check["direct_event_projection_supported"] = (
                direct_event_projection_supported
            )
            statement_anchor_check["direct_labeled_field_projection_supported"] = (
                direct_labeled_field_projection_supported
            )
            statement_anchor_check[
                "direct_allocation_citation_projection_supported"
            ] = direct_allocation_citation_projection_supported
            statement_anchor_check[
                "direct_complete_wording_projection_supported"
            ] = direct_complete_wording_projection_supported
            if direct_complete_wording_projection_supported:
                statement_anchor_check["status"] = "passed"
                statement_anchor_check["relationship_compatible"] = True
                statement_anchor_check["validation_mode"] = str(
                    complete_wording_projection["validation_mode"]
                )
            elif direct_labeled_field_projection_supported:
                # A direct date value intentionally relies on the question for
                # its subject. Preserve the ordinary anchor result above while
                # recording the stronger artifact-and-label-bound validation.
                statement_anchor_check["status"] = "passed"
                statement_anchor_check["relationship_compatible"] = True
                statement_anchor_check["validation_mode"] = (
                    "direct_labeled_field_projection"
                )
            elif direct_allocation_citation_projection_supported:
                statement_anchor_check["validation_mode"] = (
                    "direct_allocation_citation_projection"
                )
            elif direct_scalar_projection_supported:
                # A scalar-only answer may intentionally fail the ordinary
                # subject/predicate anchor: its subject is supplied by the
                # user's question. Preserve that raw result above while making
                # the effective question-bound validation state explicit.
                statement_anchor_check["status"] = "passed"
                statement_anchor_check["relationship_compatible"] = True
                statement_anchor_check["validation_mode"] = "direct_scalar_projection"
            elif direct_event_projection_supported:
                statement_anchor_check["validation_mode"] = "direct_event_projection"
            else:
                statement_anchor_check["validation_mode"] = "source_anchor"
            earned_evidence_backed = (
                not insufficient_requested
                and citation_check.get("status") == "passed"
                and bool(citation_refs)
                and statement_anchor_check.get("status") == "passed"
                and relationship_supported
            )
            if not earned_evidence_backed:
                answer_text = _question_specific_insufficient_evidence_answer(question)
                citation_refs = []
            label = "evidence_backed" if earned_evidence_backed else "insufficient_evidence"
            presented_as_fact = earned_evidence_backed
            supporting_result_count = snapshot.get("result_count", 0) if earned_evidence_backed else 0
            output_mode = "ollama_answer" if earned_evidence_backed else "insufficient_evidence"
            if earned_evidence_backed and direct_labeled_field_projection_supported:
                trust_label_reason = (
                    "Ollama generated this answer; deterministic citation-resolution and span checks "
                    "passed, and an artifact-bound labeled-field projection matched every explicit "
                    "contract identifier in the question."
                )
            elif earned_evidence_backed and direct_complete_wording_projection_supported:
                trust_label_reason = (
                    "Ollama generated this answer; deterministic citation-resolution and span "
                    "checks passed, and one cited clause supplied every requested wording facet."
                )
            elif earned_evidence_backed and direct_allocation_citation_projection_supported:
                trust_label_reason = (
                    "Ollama generated this answer; deterministic citation-resolution and span checks "
                    "passed, and one cited source clause bound every named actor to its percentage."
                )
            elif earned_evidence_backed and direct_scalar_projection_supported:
                trust_label_reason = (
                    "Ollama generated this answer; deterministic citation-resolution and span checks "
                    "passed, and a question-bound scalar projection matched the cited source."
                )
            elif earned_evidence_backed and direct_event_projection_supported:
                trust_label_reason = (
                    "Ollama generated this answer; deterministic citation-resolution and span checks "
                    "passed, and a question-bound event projection retained the cited event."
                )
            elif earned_evidence_backed:
                trust_label_reason = (
                    "Ollama generated this answer and deterministic citation-resolution, span, and "
                    "source-anchor checks passed for the cited answer."
                )
            else:
                trust_label_reason = (
                    "Ollama did not produce a citation-checked direct answer from the scoped evidence."
                )
            if not answer_text:
                answer_text = _question_specific_insufficient_evidence_answer(question)
            evidence_refs = sorted(
                {
                    f"search_snapshot:{snapshot.get('search_snapshot_id')}",
                    *[
                        ref
                        for chunk in chunks
                        for ref in (
                            f"artifact:{chunk.get('artifact_id')}",
                            f"evidence_chunk:{chunk.get('evidence_chunk_id')}",
                            str(chunk.get("derived_representation_ref") or ""),
                        )
                        if ref
                    ],
                }
            )
            model_run = {
                "schema_version": "cs.vs5_model_run.v0",
                "provider": "ollama",
                "generation_model": generation_model,
                "embedding_model": embedding_model,
                "embedding_status": chunks_result.get("embedding_status"),
                "evidence_chunk_count": len(chunks),
                "response_metadata": model_output.get("_ollama_response_metadata", {}),
                "model_json_valid": True,
            }
            value_plane = _vs5_value_plane_metadata(
                output_kind="conversation_answer",
                model_provider=model_provider,
                output_mode=output_mode,
                trust_label=label,
                trust_label_reason=trust_label_reason,
                generation_model=generation_model,
                embedding_model=embedding_model,
                citation_refs=citation_refs,
                citation_check_refs=citation_check_refs,
                earned_evidence_backed=earned_evidence_backed,
            )
        else:
            statement_anchor_check = {
                "status": "not_verified",
                "semantic_faithfulness_state": "not_verified",
            }
            if has_relevant_evidence:
                evidence_refs.extend(
                    ref
                    for result_row in snapshot.get("results", [])
                    for ref in result_row.get("evidence_refs", [])
                )
            supporting_result_count = snapshot.get("result_count", 0) if has_relevant_evidence else 0
            if model_provider == "ollama" and has_relevant_evidence:
                label = "extractive_fallback"
                output_mode = "extractive_fallback"
                trust_label_reason = "Ollama was unavailable; Ask degraded to extractive fallback without evidence_backed or presented_as_fact labels."
                answer_text = "Potentially relevant evidence was found, but Ollama was unavailable. Inspect the attached evidence refs before treating this as fact."
            else:
                label = "template_fallback" if has_relevant_evidence else "insufficient_evidence"
                output_mode = "template_fallback" if has_relevant_evidence else "insufficient_evidence"
                trust_label_reason = (
                    "Current Ask path is a template fallback; direct citation-grounded answer checks have not run."
                    if has_relevant_evidence
                    else "No meaningful supporting evidence matched the question."
                )
                answer_text = (
                    "Potentially relevant evidence was found, but this slice has not generated a direct citation-grounded answer. Inspect the attached evidence refs before treating this as fact."
                    if has_relevant_evidence
                    else _question_specific_insufficient_evidence_answer(question)
                )
            presented_as_fact = False
            model_run = {
                "schema_version": "cs.vs5_model_run.v0",
                "provider": model_provider,
                "generation_model": generation_model if model_provider == "ollama" else None,
                "embedding_model": embedding_model if model_provider == "ollama" else None,
                "embedding_status": chunks_result.get("embedding_status"),
                "evidence_chunk_count": len(chunks_result.get("chunks", [])),
                "model_json_valid": False,
                "fallback_reason": model_error,
            }
            value_plane = _vs5_value_plane_metadata(
                output_kind="conversation_answer",
                model_provider=model_provider,
                output_mode=output_mode,
                trust_label=label,
                trust_label_reason=trust_label_reason,
                generation_model=generation_model if model_provider == "ollama" else None,
                embedding_model=embedding_model if model_provider == "ollama" else None,
                citation_refs=citation_refs,
                citation_check_refs=citation_check_refs,
            )
        answer_base = {
            "schema_version": "cs.conversation_answer.v0",
            "conversation_id": conversation_id,
            "question": question,
            "scope": scope,
            "label": label,
            "trust_state": label,
            "presented_as_fact": presented_as_fact,
            **value_plane,
            "answer": answer_text,
            "search_snapshot_id": snapshot.get("search_snapshot_id"),
            "search_result_count": snapshot.get("result_count", 0),
            "supporting_result_count": supporting_result_count,
            "meaningful_question_terms": sorted(meaningful_question_terms),
            "matched_terms": sorted(matched_terms),
            "evidence_refs": evidence_refs,
            "audit_refs": [],
            "model_run": model_run,
            "prompt_boundary": prompt_boundary,
            "statement_anchor_check": statement_anchor_check,
            "semantic_faithfulness_state": "human_required" if model_provider == "ollama" else "not_verified",
            "unsupported_assertions_labeled": not presented_as_fact,
            "created_at": utc_now(),
        }
        answer = dict(answer_base)
        answer["answer_id"] = f"answer_{_json_hash(answer_base)[:16]}"
        _write_json(self.answer_path(answer["answer_id"]), answer)
        event = self.append_audit(
            "conversation.answer.created",
            scope,
            {"type": "conversation_answer", "id": answer["answer_id"]},
            {
                "conversation_id": conversation_id,
                "label": label,
                "search_snapshot_id": snapshot.get("search_snapshot_id"),
                "search_result_count": snapshot.get("result_count", 0),
                "supporting_result_count": supporting_result_count,
                "output_mode": answer.get("output_mode"),
                "trust_label": answer.get("trust_label"),
                "trust_label_reason": answer.get("trust_label_reason"),
                "model_provider": answer.get("model_provider"),
                "model_mode": answer.get("model_mode"),
                "citation_refs": answer.get("citation_refs", []),
                "citation_check_refs": answer.get("citation_check_refs", []),
                "presented_as_fact": answer.get("presented_as_fact"),
                "prompt_boundary": answer.get("prompt_boundary"),
                "model_run": answer.get("model_run"),
            },
        )
        answer["audit_refs"] = [f"audit:{search_result['audit_event']['event_id']}", f"audit:{event['event_id']}"]
        _write_json(self.answer_path(answer["answer_id"]), answer)
        return {"answer": answer, "search_snapshot": snapshot, "audit_events": [search_result["audit_event"], event]}

    def ingest_artifact_bytes(
        self,
        data: bytes,
        *,
        filename: str,
        tenant_id: str,
        owner_id: str,
        namespace_id: str,
        workspace_id: str,
        source: str,
        source_ref: str | None = None,
        source_path: str | None = None,
        media_type: str,
        derived_mode: str,
        trust: str,
        lineage_from: str | None,
    ) -> dict[str, Any]:
        scope = {
            "tenant_id": tenant_id,
            "owner_id": owner_id,
            "namespace_id": namespace_id,
            "workspace_id": workspace_id,
        }
        lock_path = self._artifact_lock_path(sha256_bytes(data), scope)
        lock_path.parent.mkdir(parents=True, exist_ok=True)
        with _artifact_thread_lock(lock_path):
            with lock_path.open("a+") as lock_file:
                fcntl.flock(lock_file.fileno(), fcntl.LOCK_EX)
                try:
                    return self._ingest_artifact_bytes_locked(
                        data,
                        filename=filename,
                        tenant_id=tenant_id,
                        owner_id=owner_id,
                        namespace_id=namespace_id,
                        workspace_id=workspace_id,
                        source=source,
                        source_ref=source_ref,
                        source_path=source_path,
                        media_type=media_type,
                        derived_mode=derived_mode,
                        trust=trust,
                        lineage_from=lineage_from,
                    )
                finally:
                    fcntl.flock(lock_file.fileno(), fcntl.LOCK_UN)

    def _ingest_artifact_bytes_locked(
        self,
        data: bytes,
        *,
        filename: str,
        tenant_id: str,
        owner_id: str,
        namespace_id: str,
        workspace_id: str,
        source: str,
        source_ref: str | None = None,
        source_path: str | None = None,
        media_type: str,
        derived_mode: str,
        trust: str,
        lineage_from: str | None,
    ) -> dict[str, Any]:
        media_type = normalize_media_type(media_type, filename)
        checksum = sha256_bytes(data)
        scope = {
            "tenant_id": tenant_id,
            "owner_id": owner_id,
            "namespace_id": namespace_id,
            "workspace_id": workspace_id,
        }
        artifact_id, existing, identity_error = self._artifact_identity_for_ingest(checksum, len(data), scope)
        if identity_error is not None:
            return identity_error
        original_storage_ref = f"sha256:{checksum}"
        original_path = self.original_dir / checksum
        original_storage_status = store_content_atomically(
            original_path,
            data,
            checksum_sha256=checksum,
        )
        observed_at = utc_now()
        source_observation = {
            "type": source,
            "filename": filename,
            "media_type": media_type,
            "size_bytes": len(data),
            "ingested_at": observed_at,
        }
        if source_ref:
            source_observation["ref"] = source_ref
        if source_path:
            source_observation["path"] = source_path
        raw_text_for_safety = data.decode("utf-8", errors="replace") if trust == "untrusted" else ""
        blocked_attempts = detect_unsafe_instructions(raw_text_for_safety) if trust == "untrusted" else []
        safety = {
            "untrusted_evidence": trust == "untrusted",
            "unsafe_instruction_detected": bool(blocked_attempts),
            "blocked_attempt_count": len(blocked_attempts),
            "blocked_attempts": blocked_attempts,
            "tool_calls_created": 0,
            "action_cards_created_from_untrusted_artifact": 0,
            "external_http_calls": 0,
            "authority_expanded": False,
        }
        if existing and existing.get("scope") == scope:
            updated = dict(existing)
            source_history = list(updated.get("source_history", [])) if isinstance(updated.get("source_history"), list) else []
            if not source_history and isinstance(updated.get("source"), dict):
                source_history.append(dict(updated["source"]))
            source_history.append(source_observation)
            updated["source_history"] = source_history[-32:]
            trust_downgraded = False
            if trust == "untrusted":
                trust_downgraded = bool(
                    updated.get("trust_state") != "untrusted"
                    or updated.get("safety", {}).get("untrusted_evidence") is not True
                    or updated.get("safety", {}).get("unsafe_instruction_detected")
                    != safety["unsafe_instruction_detected"]
                )
                updated["trust_state"] = "untrusted"
                updated["safety"] = safety
                updated["source"] = source_observation
                provenance = updated.setdefault("provenance", {})
                transformations = provenance.setdefault("transformations", [])
                if "trust_forced_untrusted" not in transformations:
                    transformations.append("trust_forced_untrusted")
                if "source_rebound_to_untrusted_upload" not in transformations:
                    transformations.append("source_rebound_to_untrusted_upload")
            derived = updated.get("derived") if isinstance(updated.get("derived"), dict) else {}
            derived_status = str(derived.get("status") or "").lower()
            resolved_representation = self._resolved_derived_representation(updated)
            legacy_representation = bool(
                resolved_representation
                and resolved_representation[0].get("schema_version") == "cs.derived_representation.legacy.v1"
            )
            representation_missing = derived_status == "ready" and (
                resolved_representation is None or legacy_representation
            )
            if (derived_status in {"deferred", "unsupported"} or representation_missing) and media_type.startswith("text/"):
                later_text = data.decode("utf-8", errors="replace")
                redacted_text = redact_text(later_text)
                updated["media_type"] = media_type
                updated["derived"] = self._create_derived_representation(
                    artifact_id=artifact_id,
                    artifact_checksum_sha256=checksum,
                    text=redacted_text,
                    redacted=redacted_text != later_text,
                )
                transformations = updated.setdefault("provenance", {}).setdefault("transformations", [])
                transformation = (
                    "derived_representation_migrated"
                    if legacy_representation
                    else "derived_representation_repaired"
                    if representation_missing
                    else "derived_text_created_from_later_observation"
                )
                if transformation not in transformations:
                    transformations.append(transformation)
            _write_json(self.artifact_path(artifact_id, scope), updated)
            event = self.append_audit(
                "artifact.deduplicated",
                scope,
                {"type": "artifact", "id": artifact_id},
                {
                    "checksum_sha256": checksum,
                    "original_storage_ref": original_storage_ref,
                    "filename": redact_text(filename),
                    "media_type": media_type,
                    "size_bytes": len(data),
                    "source_type": source,
                    "effective_trust": updated.get("trust_state"),
                    "trust_downgraded": trust_downgraded,
                    "unsafe_instruction_detected": updated.get("safety", {}).get("unsafe_instruction_detected", False),
                    "derived_status": updated.get("derived", {}).get("status"),
                    "derived_representation_id": updated.get("derived", {}).get("derived_representation_id"),
                    "original_storage_status": original_storage_status,
                },
            )
            audit_events = [event]
            policy_decisions: list[dict[str, str]] = []
            if blocked_attempts:
                unsafe_event = self.append_audit(
                    "unsafe_instruction.detected",
                    scope,
                    {"type": "artifact", "id": artifact_id},
                    {
                        "ingest_event": "artifact.deduplicated",
                        "blocked_attempt_count": len(blocked_attempts),
                        "tool_calls_created": 0,
                        "action_cards_created_from_untrusted_artifact": 0,
                        "external_http_calls": 0,
                        "authority_expanded": False,
                    },
                )
                audit_events.append(unsafe_event)
                policy_decisions.append(
                    {
                        "id": f"policy_{unsafe_event['event_hash'][:16]}",
                        "decision": "deny",
                        "reason": "prompt_injection_blocked",
                        "scope": "artifact_ingest",
                    }
                )
            return {
                "artifact": updated,
                "deduplicated": True,
                "audit_event": event,
                "audit_events": audit_events,
                "policy_decisions": policy_decisions,
                "trust_downgraded": trust_downgraded,
            }

        now = observed_at
        transformations = ["hash_calculated", "original_preserved"]
        derived: dict[str, Any]
        if derived_mode == "fail":
            derived = {
                "status": "failed",
                "reason": "fixture_derived_processor_failure",
                "message": "Original artifact is preserved and derived processing can be retried.",
            }
            transformations.append("derived_failed")
        elif derived_mode == "unsupported" or not media_type.startswith("text/"):
            derived = {
                "status": "deferred",
                "reason": "unsupported_format",
                "message": "Original artifact is preserved for future parser support.",
            }
            transformations.append("derived_deferred")
        else:
            raw_text = data.decode("utf-8", errors="replace")
            redacted_text = redact_text(raw_text)
            derived = self._create_derived_representation(
                artifact_id=artifact_id,
                artifact_checksum_sha256=checksum,
                text=redacted_text,
                redacted=redacted_text != raw_text,
            )
            transformations.append("derived_text_created")

        source_record = source_observation
        record = {
            "schema_version": "cs.artifact.v0",
            "artifact_id": artifact_id,
            "checksum_sha256": checksum,
            "content_identity": {"algorithm": "sha256", "value": checksum},
            "original_storage_ref": original_storage_ref,
            "raw_original_access": {"policy": "owner_scope_required", "display": "controlled"},
            "original_size_bytes": len(data),
            "media_type": media_type,
            "trust_state": trust,
            "safety": safety,
            "scope": scope,
            "source": source_record,
            "provenance": {
                "created_at": now,
                "lineage_from": lineage_from,
                "transformations": transformations,
            },
            "derived": derived,
        }
        _write_json(self.artifact_path(artifact_id, scope), record)
        event = self.append_audit(
            "artifact.ingested",
            scope,
            {"type": "artifact", "id": artifact_id},
            {
                "checksum_sha256": checksum,
                "original_storage_ref": original_storage_ref,
                "derived_status": derived["status"],
                "trust_state": trust,
                "filename": redact_text(filename),
                "media_type": media_type,
                "size_bytes": len(data),
                "source_type": source,
                "derived_representation_id": derived.get("derived_representation_id"),
                "original_storage_status": original_storage_status,
            },
        )
        audit_events = [event]
        policy_decisions: list[dict[str, str]] = []
        if blocked_attempts:
            unsafe_event = self.append_audit(
                "unsafe_instruction.detected",
                scope,
                {"type": "artifact", "id": artifact_id},
                {
                    "blocked_attempt_count": len(blocked_attempts),
                    "tool_calls_created": 0,
                    "action_cards_created_from_untrusted_artifact": 0,
                    "external_http_calls": 0,
                    "authority_expanded": False,
                },
            )
            audit_events.append(unsafe_event)
            policy_decisions.append(
                {
                    "id": f"policy_{unsafe_event['event_hash'][:16]}",
                    "decision": "deny",
                    "reason": "prompt_injection_blocked",
                    "scope": "artifact_ingest",
                }
            )
        return {
            "artifact": record,
            "deduplicated": False,
            "audit_event": event,
            "audit_events": audit_events,
            "policy_decisions": policy_decisions,
        }

    def ingest_artifact(
        self,
        input_path: Path,
        *,
        tenant_id: str,
        owner_id: str,
        namespace_id: str,
        workspace_id: str,
        source: str,
        media_type: str,
        derived_mode: str,
        trust: str,
        lineage_from: str | None,
    ) -> dict[str, Any]:
        return self.ingest_artifact_bytes(
            input_path.read_bytes(),
            filename=input_path.name,
            tenant_id=tenant_id,
            owner_id=owner_id,
            namespace_id=namespace_id,
            workspace_id=workspace_id,
            source=source,
            source_path=str(input_path),
            media_type=media_type,
            derived_mode=derived_mode,
            trust=trust,
            lineage_from=lineage_from,
        )
